import { useState, useRef, useEffect } from "react";

const BOXTIME = [
  { no:"BT-1", label:"Cl.1", title:"Period of Charter Party and Delivery", topic:["delivery", "redelivery"],
    en:"(a) In consideration of the hire detailed in Box 25 the Owners let and the Charterers hire the vessel for the period together with any optional extension(s) thereto as indicated in Box 23. Such options, always at the Charterers’ discretion, must be declared to the Owners within the period as indicated in Box 24.\n(b) The Owners shall deliver the Vessel to the Charterers at the Place of Delivery as indicated in Box 18. Unless agreed by the Charterers to the contrary, delivery shall take place no earlier than the time/date as indicated in Box 19 and no later than the time/dates as indicated in Box 20.\nSee Clause 36.\nShould the vessel not be delivered by the date indicated in Box 20, the Charterers shall have the option of cancelling.\nIf the vessel cannot be delivered by the cancelling date, the Charterers shall, if required, declare within 24 hours after receiving notice thereof whether they cancel or will take delivery of the vessel.\nIf prior to delivery the Owners give notice to the Charterers that the Vessel will not be ready for delivery by the time/date as indicated in Box 20, the Charterers shall declare within 48 hours after receiving notice thereof from the Owners whether they cancel or will take delivery of the Vessel but without prejudice to the Charterers’ right to claim proved damages.\n(c) If the Owners are unable to deliver the Vessel at the Place of Delivery as indicated in Box 18 for any reason beyond the control of the Owners, delivery shall take place at the nearest point to the nominated Place of Delivery to which the Vessel may safely and reasonably proceed.\nThe Owners shall give notice of readiness to deliver to the Charterers and/or the Charterers’ local agents when in position to come on hire.\n(d) Delivery shall be effected at any time, day or night, Saturdays, Sundays and holidays included.\n(e) At the time of delivery the Vessel shall be clean and in all respects fit to receive goods in containers and ISO standard containers, in accordance with vessel’s description.\n(f) The Charterers’ acceptance of delivery of the Vessel shall not prejudice their rights against the Owners under this Charter Party.",
    zh:"【交船時間窗口】船東須在Box 19（最早）至Box 20（最遲/cancelling date）之間交船。若船東預見無法在cancelling date前交船，須提前通知；租家有48小時決定是否取消或接受交船。若直到cancelling date才通知，租家只有24小時決定。租家取消後不影響其損失賠償請求權。【交船條件】交船時船舶須清潔、適合裝載貨櫃，符合Part I及III描述。租家接受交船不影響其對船東的任何權利主張。", owner:["Deliver vessel on time in seaworthy state"], charterer:[] },

  { no:"BT-2", label:"Cl.2", title:"Owners' Undertaking", topic:["delivery"],
    en:"The Owners undertake that at delivery, the Vessel shall be of the description set out in Parts I and III hereof.",
    zh:"【船東保證責任】船東保證交船時船舶完全符合Part I（Box欄位填寫的商業條件）及Part III（船舶技術描述）的規格。若交船時船舶與描述不符，租家可拒絕接受交船或要求損害賠償。這是船東的核心義務，不得以任何理由免責。", owner:["Vessel must conform to description in Parts I and III at delivery"], charterer:[] },

  { no:"BT-3", label:"Cl.3", title:"Trading Limits", topic:["trading"],
    en:"The Vessel shall be employed in lawful trades within Institute Warranty Limits (IWL) and within the Trading Limits as indicated in Box 22 for the carriage of lawful goods between safe ports or places where she can safely lie always afloat. The Vessel shall not be obliged to force ice nor to follow icebreakers.\nThe Owners warrant that, as far as Owners know, at the time of signing this Charter Party, the Vessel has not traded to any countries which would make the Vessel unacceptable for calls at ports within the Trading Limits as indicated in Box 22. The Charterers shall provide a list of such countries. See Clause 34.",
    zh:"【交易範圍】船舶只能在IWL（Institute Warranty Limits，倫敦保險商保證限制）範圍內及Box 22指定的交易限制內從事合法貨物運輸，在安全港口/安全錨地之間航行，且必須能全程浮水（always afloat）。船舶無須強行破冰或跟隨破冰船前進。【黑名單聲明】船東須保證（以其知悉範圍內）交船時船舶未曾前往會導致在Box 22指定交易範圍內被列為不受歡迎的國家。詳細交易限制見Rider Cl.34。", owner:[], charterer:[] },

  { no:"BT-4", label:"Cl.4", title:"Permitted Cargoes", topic:["cargo"],
    en:"Except as provided below, the Vessel shall be used exclusively for the carriage of goods in ISO standard containers complying with the international convention for safe containers.\n(a) Uncontainerised goods may be carried only with the prior consent of the Owners and the Master provided that they are suitably prepared for carriage.\n(b) Hazardous Goods: The Owners agree that the Charterers may carry the maximum quantity as indicated in Box 26 of hazardous goods in containers provided same are loaded, stowed, discharged and documented in accordance with IMO regulations, any mandatory local requirements and regulations of the flag state. See Clause 64.\n(c) Live Animals: Live animals may be carried only with the prior consent of the Owners and the Master.\n(d) Radioactive Goods: Radioactive goods other than isotopes shall be excluded. Radioactive isotopes may be carried only with the prior consent of the Owners and the Master and provided that they are of such a category as not to invalidate the Vessel’s P&I cover.\n(e) Arms & Ammunition: Arms and ammunition may be carried only with the prior consent of the Owners and the Master.",
    zh:"【基本原則】船舶僅限裝載符合國際安全貨櫃公約的ISO標準貨櫃。【例外情況，均需船東及船長事先同意】(a)非貨櫃化散貨：需適當包裝準備；(b)危險品：依IMO規定裝載，數量見Box 26，詳見Rider Cl.64；(c)活體動物：需事先同意；(d)放射性同位素：不得危及P＆I保險效力，需事先同意；(e)武器彈藥：需事先同意。", owner:[], charterer:["Ensure cargo complies with IMO regulations and permissions"] },

  { no:"BT-5", label:"Cl.5", title:"Owners' Obligations", topic:["maintenance", "crew"],
    en:"Except as provided elsewhere in this Charter Party, the Owners shall at their expense maintain the Vessel in the Class as indicated in Box 10, in a thoroughly efficient state of hull and machinery and in every way fitted for the container service throughout the currency of this Charter Party.\nThe Owners shall, inter alia, provide and pay the cost of the following:\n(a) Container Lashings (See Clause 10(a)).\n(b) Crew Assistance with inter alia:\n(i) preparing the Vessel’s cranes, derricks, winches and/or cargo handling gear for use.\n(ii) opening and closing any hatches (other than pontoon type hatches), ramps and other means of access to goods and containers.\n(iii) docking, undocking and shifting operations in port.\n(iv) bunkering.\n(v) maintaining power during loading and discharging operations.\n(vi) instructing crane drivers and winchmen in use of Vessel’s gear.\n(vii) supervising stevedores lashing and unlashing goods and containers and the regular checking of lashings at sea when weather conditions permit (See Clause 10(d)(ii)).\n(viii) monitoring, recording performances and, when available, supplying labour for the repairing of the Charterers’ refrigeration machinery, weather permitting (See Clause 17(b)).\nThe above services shall be rendered by the crew if required, provided port and local labour regulations permit, and except when repairing the Charterers’ refrigeration machinery any overtime incurred shall be for the account of the Owners.\n(c) Documentation: Any documentation relating to the Vessel that may be required to permit the Vessel to trade within the limits as indicated in Box 22, including, but not limited to:\n; certificates of financial responsibility for oil pollution\n; valid international tonnage certificate\n; Suez and Panama tonnage certificates\n; certificate of Registry\n; certificates relating to the strength and/or serviceability of the Vessel’s gear\n(See Clause 11(a)).\n(d) Insurance for the Vessel (See Clause 18).\n(e) Fumigation and/or deratisation: The provision of certificates thereof at the commencement of the Charter Party and renewal thereof throughout the Charter Party, except if required due to Charterers’ cargo, in which case costs are for Charterers.\n(f) Smuggling: In the event of smuggling by the Master, Officers and/or crew, the Owners shall bear the cost of any fines, taxes or imposts levied and the Vessel shall be off hire for any time lost as a result thereof (See Clause 6(p)).",
    zh:"【船東主要義務】船東須以自費維持船舶於Box 10所示船級，保持船體、機械完全有效狀態，適合貨櫃服務。具體義務包括：(a)提供並維護足夠的貨櫃綁固設備（詳見Cl.10）；(b)船員協助（開關艙口/靠離泊/加油/維持電力/指導起重機操作/監督裝卸綁紮/監控冷凍貨設備等）；(c)提供所有必要的貿易文件及證書（包括油污財務責任證書、噸位證書、船籍證書等）；(d)維持船舶保險（見Cl.18）；(e)提供並更新除蟲/滅鼠證書（除非因租家貨物需要，則由租家負責）；(f)走私責任：若船長/船員走私，船東承擔罰款並負off-hire責任。", owner:["Maintain vessel in thoroughly efficient state throughout charter", "Provide container lashings", "Crew assistance with cargo operations", "All certificates and documentation"], charterer:[] },

  { no:"BT-6", label:"Cl.6", title:"Charterers' Obligations", topic:["cargo", "hire", "bl"],
    en:"Except as provided elsewhere in this Charter Party, the Charterers shall provide and pay the costs of the following throughout the currency of this Charter Party.\n(a) Provision of Details: The provision of full and accurate details of goods and containers (including any documentation required at any ports of call), their weights and stowage positions to the Master as early as possible but not later than upon arrival at the port of loading, with regular updating thereof and the provision of a full and accurate plan of the stowage of all goods and containers actually loaded prior to sailing. Such details shall include:\n(i) gross weights of containers,\n(ii) any feature of the goods requiring attention by the crew during the voyage, including, but not limited to, any hazardous or other dangerous feature and/or the need for carriage within a specified temperature range.\n(b) Instructions to the Master: The Master, although appointed by the Owners shall at all times during the currency of this Charter Party be under the orders and directions of the Charterers as regards employment and agency. The Charterers shall be obliged at all times to furnish the Master with full and timely instructions.\n(c) Stevedoring: (See Clause 10(d)(i)).\n(d) Charterers’ Lashings: (See Clause 10(b)).\n(e) Condition of Containers: The Charterers warrant that all containers carried pursuant to this Charter Party have been constructed to a design approved by a Classification Society and are properly maintained.\n(f) Stowage in Containers: The correct stowage and safe securing of all goods within containers (including securing to flat rack containers) to withstand the rigours of the voyage.\n(g) Stowage Planning: (See Clause 10(c)).\n(h) Operating Expenses: All port charges, light and canal dues, pilotage, towage, consular charges, and all other charges and expenses relating to the operation of the Vessel and hazardous goods carried not otherwise provided for in this Charter Party, other than charges or expenses relating to the crew, compulsory garbage removal to be paid for by Charterers unless actually disposed of same.\n(i) Bunker Fuel: (See Clause 12).\n(k) Agency Costs: All agency fees and expenses for normal ship’s husbandry at all ports or places of call.\n(l) Damage to Vessel: Any damage to the Vessel or loss or damage to its equipment caused by stevedores during the currency of this Charter Party shall be reported by the Master to the Charterers or their agents, in writing, within 24 hours of the occurrence or as soon as possible thereafter but latest when the loss or damage could have been discovered by the exercise of due diligence. The Master shall endeavour to obtain written acknowledgment by the party causing loss or damage unless it is made good in the meantime. The Charterers shall pay for stevedore damage whether or not payment has been made by stevedores to the Charterers.\nDamage for which the Charterers are responsible affecting seaworthiness or the proper working of the Vessel and/or her equipment, shall be repaired without delay to the Vessel after each occurrence in the Charterers’ time and shall be paid for by the Charterers. Other repairs to damage for which the Charterers are responsible shall also be carried out in the Charterers’ time but, if this is not possible, such repairs shall be carried out whilst the Vessel is in drydock in the Owners’ time provided this does not interfere with the Owners’ repair work, or by the Vessel’s crew at the Owners’ convenience. All costs of such repairs shall be for the Charterers’ account. The actual cost of such repairs provided with proper supporting invoices shall be for Charterers’ account.\n(m) Redelivery: Redelivery of the Vessel at the Place of Redelivery as indicated in Box 21, unless agreed by the Owners or provided elsewhere to the contrary, in the same condition to that pertaining when the Vessel was delivered, fair wear and tear excepted, at the end of the period as indicated in Box 23. The Charterers shall give the Owners one month 30/25/15/10 days’ approximate notice prior to expected redelivery and Charterers to give 5/3/1 days’ notice of redelivery.\nAt the time of redelivery the Vessel shall be clean and fit to load goods and ISO standard containers. If the Charterers have changed the configuration of the Vessel to carry different size ISO standard containers or non ISO standard containers, they shall, in their time and at their cost, prior to redelivery, return the Vessel to its previous configuration, unless the Owners agree to waive this requirement, in which case the Charterers shall return the Vessel to its previous configuration, at their cost, after redelivery at such time and place stipulated by the Owners but in the Owners’ time. Without prejudice to any other claim the Owners may have under this Charter Party the Owners shall not be obliged to accept redelivery of the Vessel before it is returned to its previous configuration.\n(n) Additional Premiums: All additional premiums for hull and machinery, war risks, including blocking and trapping, or protection and indemnity insurance incurred by the Owners over and above the premiums payable by the Owners. The Owners shall allow the Charterers to arrange these additional covers on their behalf if the Charterers so request and if the proposed insurers and terms are acceptable to the Owners. If the Charterers arrange such insurance the Charterers’ insurers shall confirm cover latest 24 hours before the Vessel is due to be exposed to the risk so insured (See Clause 18).\n(o) Advances to Master: The Charterers shall procure that their local agents at Singapore, Hong Kong, Taiwan and all ports of call shall, upon request by the Owners or Master, make funds available to the Master for disbursements subject to 2.5% commission, which advances the Charterers may recoup from the Owners by deduction from the hire payments in accordance with Clause 7(e). Owners to give Charterers 7 days pre-notice for such advance of cash prior vessel’s calling at the port where cash is to be advanced to Master.\n(p) Contraband: In the event that contraband and/or unmanifested drug or goods are found to have been shipped as part of the goods and/or in containers on board, any fines, taxes or imposts levied shall be for the Charterers’ account, and the Vessel shall remain on hire during any time lost as a result thereof, unless it can be established that the Master, Officers and/or crew are involved in smuggling (See Clause 5(f)). In this event any security required shall be provided by the Charterers.",
    zh:"【租家主要義務】租家須負擔整個租期的以下費用：(a)貨物資料提供：在抵達裝貨港前及時提供完整準確的貨物明細、重量、積載位置，並提供已裝貨物的積載計劃；(b)指揮船長：船長雖由船東任命，但在employment及agency事務上須服從租家指示；(c)裝卸費用：負責並支付所有裝卸作業（含接收、裝載、搬運、積載、綁紮、卸貨、清點等）費用；(d)租家綁固材料：若需額外綁固材料，由租家提供；(e)貨櫃狀況保證：保證所有貨櫃均已獲Classification Society認可並妥善維護；(f)積載規劃：確保積載符合穩性要求；(g)港口費用：支付所有港口費、燈塔稅、運河費、引水費、拖輪費、領事費及其他船舶運營費用（除船員相關費用外）；(h)燃油：見Cl.12；(i)代理費：支付所有港口代理費用。", owner:[], charterer:["Provide full cargo details and stowage plan to Master", "Pay all port charges, dues, pilotage, towage, consular charges", "Pay bunker fuel costs", "Pay all agency fees"] },

  { no:"BT-7", label:"Cl.7", title:"Hire", topic:["hire"],
    en:"(a) Rate: The Charterers shall pay hire at the rate stated in Box 25, per day or pro rata for part of a day, from the time the Vessel is delivered to the Charterers until her redelivery to the Owners. All calculation of hire shall be made by reference to Universal Time Co-ordinated (U.T.C.).\n(b) Payment: Payment of hire shall be made in cash in full and without discount, semi-monthly 15 days in advance. If hire or any instalment thereof is not paid as aforesaid, the Charterers shall pay interest at the rate of 0.1 per cent per day on the amount outstanding from and including the due date until the date of payment.\n(c) Default: In default of punctual and regular payment as herein specified, the Owners may require the Charterers to make payment of the amount due within 96 running hours of receipt of notification from the Owners, failing which the Owners will have the right to withdraw the Vessel without prejudice to any claim the Owners may have against the Charterers under this Charter Party. Further, so long as the hire remains unpaid, the Owners shall be entitled to suspend the performance of any and all of their obligations hereunder and shall have no responsibility whatsoever for any consequences thereof in respect of which the Charterers hereby indemnify the Owners. Hire shall continue to accrue and any extra expenses resulting from such suspension shall be for the Charterers’ account.\n(d) Redelivery Adjustment: Should the Vessel be on her voyage towards the Place of Redelivery at the time payment of hire becomes due, said payment shall be made for the estimated time necessary to complete the voyage, less disbursements made by the Charterers for the Owners’ account, including the estimated value of bunker fuel on board at redelivery. When the Vessel is redelivered to the Owners, any difference shall be refunded to or paid by the Charterers as appropriate, but not later than three months after redelivery of the Vessel.\n(e) Deductions: On production of supporting vouchers the Charterers shall be entitled to deduct from payments of hire any expenditure incurred on behalf of the Owners which may be payable by the Owners under this Charter Party. If such expenditure is incurred in a currency other than that in which hire is payable, conversion into such currency for the purpose of deduction shall be effected at the rate of exchange at the place of the bank where hire is paid prevailing on the date when the expenditure was incurred.\n(f) Extension: The Charterers shall arrange the Vessel’s trading so as to permit redelivery at the place and in the period as indicated in Boxes 21 and 23 respectively. If the Vessel is not chartered for a minimum/maximum period and the Vessel is sent on a final voyage reasonably calculated to allow redelivery within such period at the Place of Redelivery as provided under this Charter Party, and the voyage is prolonged for reasons beyond the Charterers’ control, the Charterers shall have the use of the Vessel at the rate and on the conditions of this Charter Party for such extended time as may be required for completion of said voyage and redelivery aforesaid.",
    zh:"【租金費率】依Box 25費率按日計算（pro rata for part of a day），從交船時起至還船時止，以UTC計算。【支付方式】預付，每半個月（15天）支付一次，以現金全額支付，不得扣減。【遲付後果】若未按時支付，船東可要求租家在收到通知後96運行小時內付清，否則有權withdraw船舶，且在欠款期間有權暫停履行所有義務（所有因暫停產生的費用由租家負責），hire繼續累積。逾期未付利息按每日0.1%計算。【最後航次調整】若在最後航次中hire到期，按預計完成航次所需時間計算，扣除租家代墊的Owners費用及預估還船燃油價值；還船後三個月內多退少補。【扣款權利】租家可憑憑證從hire中扣除代Owners墊付的費用，但需換算成hire計價貨幣。", owner:[], charterer:["Pay hire semi-monthly 15 days in advance", "Interest at 0.1% per day on late payments"] },

  { no:"BT-8", label:"Cl.8", title:"Off Hire", topic:["offhire"],
    en:"After delivery in accordance with Clause 1 hereof, the Vessel shall remain on hire until redelivered in accordance with Clause 6(m), except for the following periods:\n(a) Unable to Comply with Instruction: If the Vessel is unable to comply with the instructions of the Charterers on account of:\n(i) any damage, defect, breakdown, or deficiency of the Vessel’s hull, machinery, equipment or repairs or maintenance thereto, including the drydocking, excepting those occasions when Clause 6(l) applies,\n(ii) any deficiency of the Master, Officers and/or crew, including the failure, refusal or inability of the Master, Officers and/or crew to perform service immediately required, whether or not within the control of the Owners,\n(iii) arrest of the Vessel at the suit of a party where a claim is not caused by the Charterers, their servants, agents or sub-contractors (See Clause 5(f)),\n(iv) any delay occasioned by any breach by the Owners of any obligation or warranty in this Charter Party,\nIf any of the above incidents affect the full use of the Vessel, it shall be off hire. If they partially affect the use of the Vessel, it shall be off hire for time actually lost to the extent such incidents affect the Charterers’ use of the Vessel (See also Clause 11(b)).\n(b) Deviation: In the event of the Vessel deviating (which expression includes putting back, or putting into any port or place other than that to which she is bound under the instructions of the Charterers) other than to save life or property, hire shall cease to be payable from the commencement of such deviation until the time when the Vessel is again ready to resume her service from a position not less favourable to the Charterers than that at which the deviation commenced, provided always that due allowance shall be given for any distance made good towards the Vessel’s destination and any bunkers saved. However, should the Vessel alter course to avoid bad weather or be driven into port or anchorage by stress of weather, the Vessel shall remain on hire and all costs thereby incurred shall be for the Charterers’ account.\n(c) Blocking and Trapping: If during the currency of this Charter Party the Vessel is blocked or trapped in circumstances where Clause 19(b) applies, the Vessel shall be off hire for the period blocked or trapped. If the Vessel is blocked or trapped for a period of 365 days this Charter Party shall be terminated.\n(d) Requisitions: Should the Vessel be requisitioned by any government or governmental authority during the period of this Charter Party, it shall be off hire during the period of such requisition and any hire or other compensation paid by any government or governmental authority in respect of such requisition shall be paid to the Owners. However, the Charterers shall have the option of cancelling the balance period of this Charter Party, provided this option is exercised within 14 days of receipt of notice of requisition.\n(e) Loss of Time: In the event of loss of time for which the Owners are responsible, including but not limited to terms of employment of Master, Officers and/or crew, the Vessel shall be off hire for the time thereby lost. Any time during which the Vessel is off hire under this Charter Party may be added to the charter period, at the option of the Charterers. Such option shall be declared not less than two months before expected redelivery, or latest two weeks after the event if less than two months before expected redelivery.",
    zh:"【基本原則】交船後船舶持續計租直至依Cl.6(m)還船，以下情況除外。【停租原因】(a)無法依指示作業：因船舶損壞/故障/缺陷、船員不足/怠工/拒絕服務、非因租家引起的扣押、船東違反合約等，全面影響使用則全部停租，部分影響則按實際損失時間比例停租；(b)偏航：擅自偏離航線，從偏航開始到恢復到不比偏航前更不利的位置（扣除已完成距離及節省燃油），途中因惡劣天氣改道或被迫進港則仍計租；(c)封鎖/被困：因Cl.19(b)情況被封鎖或困住，最長365天後合約自動終止；(d)徵用：政府或當局徵用期間停租，政府支付的任何補償歸船東，租家有14天內取消餘期的選擇權；(e)因船東責任造成的時間損失：停租期間可由租家選擇加回租期（需在預計還船前兩個月或事件發生後兩週內宣告）。", owner:[], charterer:[] },

  { no:"BT-9", label:"Cl.9", title:"Loss of Vessel", topic:["offhire"],
    en:"Should the Vessel be lost, or become a constructive total loss, hire shall cease at noon on the day of her loss or constructive total loss, and if missing, from noon on the date when last heard of, and any hire paid in advance and not earned shall be returned to the Charterers and payment of any hire due shall be suspended until the Vessel is reported safe.",
    zh:"【船舶滅失】船舶滅失或推定全損時，hire從滅失當日正午起停計；失蹤則從最後聯絡日正午起停計。已預付未賺取的hire須退還租家；到期未付的hire暫停至船舶確認安全為止。", owner:[], charterer:[] },

  { no:"BT-10", label:"Cl.10", title:"Lashings and Stevedoring", topic:["cargo", "lashing", "maintenance"],
    en:"(A) Owners’ Lashings: The Owners shall supply and maintain in good working order throughout the currency of this Charter Party sufficient lashing and securing equipment to facilitate the proper lashing and securing in accordance with the plan supplied by the Owners of the maximum number of ISO standard containers which may be carried in accordance with the details provided in Part III Clause 65 hereto. The Owners further warrant that both the strength of the lashings and the design of the lashing pattern are adequate for the stowage in accordance with Part III Clause 65 hereto and that these have been approved by the Vessel’s Classification Society.\n(B) Charterers’ Lashings: Should any additional or alternative lashings to those supplied by the Owners be required, these shall be supplied by the Charterers at their expense. Should the Charterers supply gear, equipment or stores, the Master shall keep a record of it and care for it. Such gear, equipment or stores shall be redelivered to the Charterers at the time required by the Charterers in the same condition as supplied, fair wear and tear excepted. However, Master, officers and crew are to make utmost diligence to protect Charterers’ property.\n(C) Stowage Planning: The Charterers shall ensure that stowage is effected in accordance with the requirements of this Charter Party and of the Vessel’s stability including, inter alia, that stack and tier weights are not exceeded and that heavy containers are not stowed over light containers on or under deck, except with the Master’s prior approval.\n(D) Stevedoring:\n(i) The Charterers shall provide and pay for the cost of all stevedoring operations during the currency of this Charter Party including, inter alia, receipt, loading, handling, stowing, lashing, securing, unsecuring, unlashing, unstowing, discharging, tallying and delivering of all uncontainerised goods and containers and shall be liable to the Owners for all loss or damage caused to the Vessel by the improper or careless performance of such operations.\n(ii) The Master shall supervise stevedores undertaking the tasks outlined in Clause 10(d)(i) to ensure that these are done correctly and to his satisfaction. The Master shall ensure that all lashings are regularly checked whilst at sea, weather permitting.\n(E) Liability: Except in respect of the failure of any lashing supplied by the Charterers, the Owners shall be responsible, subject to the provisions of Clause 17, for the consequences of the failure of any lashings or lashing pattern design or execution or the failure to properly service lashings during the voyage.",
    zh:"【船東綁固義務】船東須提供並在整個租期維護足夠的綁固及固定設備，足以按Part III Cl.65所示最大數量的ISO標準貨櫃進行妥善綁紮，且綁固強度及設計須經船舶Classification Society批准。【租家額外綁固】若租家需要額外或替代的綁固材料，由租家自費提供；船長須保管記錄，並在還船前以同等良好狀態歸還（正常損耗除外），船長/船員須盡力保護租家財產。【積載規劃】租家確保積載符合合約及船舶穩性要求，包括不超過層重限制，重箱不壓輕箱（除非船長事先批准）。【裝卸費用及責任】租家負擔並支付所有裝卸費用，包括接收、裝載、綁紮、積載、卸貨等，並對因不當裝卸造成的船損負責；船長須監督裝卸確保正確執行，並在海上天氣允許時定期檢查綁紮。【責任歸屬】除租家自提供的綁固材料失效外，船東對所有綁固設計/執行失敗的後果負責（依Cl.17規定）。", owner:["Supply and maintain sufficient lashing equipment approved by Classification Society", "Pay shore crane costs if vessel gear breaks down"], charterer:["Pay for all stevedoring operations", "Liable for damage caused by improper stevedoring"] },

  { no:"BT-11", label:"Cl.11", title:"Vessel's Gear & Equipment", topic:["maintenance"],
    en:"(a) Regulations: The Vessel’s cargo gear if any, and any other equipment shall comply with the regulations of the countries to which the Vessel will be employed and the Owners shall ensure that the Vessel is at all times during the currency of this Charter Party in possession of valid certificates of efficiency to comply with such regulations. If stevedores are not permitted to work due to failure of the Master and/or the Owners and/or the Owners’ agents to comply with the aforementioned regulations or because the Vessel is not in possession of such valid certificates of efficiency, then the Charterers may suspend hire for the time lost thereby and the Owners shall pay all expenses incurred incidental to and resulting from such failure (See Clause 5(c)).\n(b) Condition: All cargo handling gear, including derrick(s), crane(s) and winch(es) if any, shall be kept in good working order and the Owners shall maintain, repair and/or replace such gear whenever necessary. In the event of loss of time due to a breakdown of derrick(s), crane(s) or winch(es) for any period by reason of disablement or insufficient power, hire shall be reduced pro rata for the period of such inefficiency in relation to the number of hatches affected, unless caused by mishandling by the Charterers or their servants. If the Charterers continue working by using locally available shore-crane(s), the Owners shall pay such charges but not exceeding the hire payable for such period, in which case the Vessel shall not be off hire pro rata as stipulated above. The Vessel shall, however, be pro-rata off hire if shore-cranes are not available during stoppages of derrick(s), crane(s) or winch(es) and all other direct and proven unavoidable expenses thereby incurred shall be for the Owners’ account.\n(c) Suez and Panama Canal: The Vessel shall be maintained during the currency of this Charter Party with all necessary fittings for Suez and Panama Canal transit in good working order.\n(d) Refrigeration: The Owners shall ensure that all refrigeration facilities as described in Part III Clause 65 are maintained in good working order throughout the currency of this Charter Party.\n(e) Lighting: The Owners shall ensure that the Vessel will supply sufficient lighting to deck and holds to permit 24 hour working free of expense to the Charterers and that such lighting will comply with the port regulations at all ports of call throughout the currency of this Charter Party.",
    zh:"【設備合規】船舶裝卸設備須符合所有交易國家的法規，船東須確保船舶在整個租期持有有效的效率證書。若因船長/船東/代理未遵守規定或缺乏有效證書，導致理貨員無法作業，租家可暫停hire，費用由船東承擔。【設備維護】所有裝卸設備（起重機/吊桿/絞機等）須保持良好狀態，船東負責維修保養及更換。起重機/吊桿/絞機故障導致時間損失時，按受影響的艙口數比例減租（除非因租家不當操作引起）。若租家使用本地岸機繼續作業，船東支付岸機費用（但不超過該期間的hire），此時不再按比例停租；若無可用岸機，則按比例停租且所有直接可證明的不可避免費用由船東承擔。【蘇伊士/巴拿馬】船舶在整個租期保持蘇伊士及巴拿馬運河通過所需的所有配件有效運作。【冷凍設施】確保Part III Cl.65所述的所有冷凍設施在整個租期保持良好運作狀態。【照明】免費提供並維護符合港口法規的充足電力照明，確保24小時作業。", owner:["Maintain cargo gear in good working order", "Pay shore crane costs during gear breakdown"], charterer:[] },

  { no:"BT-12", label:"Cl.12", title:"Bunker Fuel", topic:["bunker"],
    en:"(a) Quantity at Delivery/Redelivery: The Vessel shall be delivered with approximately the quantity of fuel as indicated in Box 16 and, unless indicated to the contrary in Box 17, the Vessel shall be redelivered with an approximately similar quantity, provided that the quantity of fuel at redelivery is at least sufficient to allow the Vessel to reach safely the nearest port at which fuel of the required type is available. See Clause 31.\n(b) Pre and Post Charter Bunkering: Provided that it can be accomplished without hindrance to the operation of the Vessel, the Owners shall allow the Charterers to bunker for the account of the Charterers prior to delivery and the Charterers shall allow the Owners to bunker for the account of the Owners prior to redelivery, in both cases by prior arrangement between the parties.\n(c) Purchase Price: Unless otherwise stated in Boxes 16 and 17 the Charterers shall purchase the fuel on board at delivery and the Owners shall purchase the fuel on board at redelivery at the Platts Oil Gram mean prices at the ports and dates of delivery and redelivery, respectively, or the nearest bunkering port thereto.\n(d) Specification: As per vessel’s descriptions. The Charterers shall supply fuel of the B.S.M.A. 100:1989 specification or any amendment thereto as indicated in Box 4.\n(e) Consumption: The Vessel’s fuel consumption in port and at sea shall not exceed the amounts shown in Part III Clause 65, at all times for port consumption and in smooth water with winds not exceeding Beaufort Scale 2 for consumption at sea.\n(f) Bunkering: The Chief Engineer shall co-operate with the Charterers’ bunkering agents and fuel supplier and comply with their requirements during bunkering, including, but not limited to, checking, verifying and acknowledging readings or soundings, meters etc. before, during and/or after delivery of fuel.\nThree (3) samples of all fuel shall be taken during delivery, sealed and signed by suppliers, Chief Engineer and the Charterers’ agent, each of whom should retain one sample. If any claim should arise in respect of the quality or specification of the fuel supplied, the Owners and the Charterers agree to have samples of the fuel analysed by a mutually agreed qualified analyst. All bunker samples testing arranged by the Owners to be for Owners’ account, unless requested by Charterers.",
    zh:"【交還船油量】交船時帶約Box 16所示的燃油量；還船時帶約Box 17所示的量（或相似數量），但至少須足以安全到達最近的可加油港口，詳見Rider Cl.31。【交還船前加油】在不妨礙船舶運營的前提下：交船前租家可為自己的帳戶加油；還船前船東可為自己的帳戶加油。【燃油規格】按船舶描述要求的BSMA 100:1989規格或其修訂版（詳見Rider Cl.86/92/98）。【消耗保證】在Beaufort 2級以下平靜海況，港口及海上燃油消耗不超過Part III Cl.65所示數量。【加油協調】大副須配合租家的加油代理，包括確認測量/液位/流量等讀數。【油樣存證】加油時取三份樣本，由供應商/大管輪/租家代理各保存一份，如有爭議由雙方協議的合格分析師化驗（Rider Cl.71：化驗費用由船東承擔）。", owner:["Pay for bunkers at redelivery"], charterer:["Pay for bunkers at delivery", "Coordinate bunkering with Chief Engineer"] },

  { no:"BT-13", label:"Cl.13", title:"Charterers' Requirements", topic:["cargo", "crew"],
    en:"(a) Plans\nOn signing this Charter Party the Owners shall, if the Charterers so request, furnish the Charterers with the following documents in English:\n(i) General Arrangement Plan\n(ii) Capacity Plan\n(iii) Container Stowage Plan\n(iv) Plan of Deck and (where the Vessel not cellular) Under-Deck Container Lashing Plan approved by the Vessel’s Classification Society\n(v) Trim and Stability Book\n(vi) Hydrostatic Curves Plan\n(vii) Loading Scale\n(viii) Tank Plan\nand any other operational documents that the Charterers may reasonably request and which are necessary for the safe and efficient operation of the Vessel. All documents received by the Charterers shall be returned to the Owners on redelivery.\n(b) Flag, Funnel, Name and Configuration\nThe Charterers, if required, shall be allowed to fly their house flag, paint the funnel in the Charterers’ colours and/or the name of the Line on the Vessel’s side, change the Vessel’s name subject to the authorities’ approval, and/or change the Vessel’s container stowage configuration to carry different sized containers, all during the currency of this Charter Party. If the Charterers elect to exercise any or all of these options all alterations necessary shall be effected during the Charterers’ time and at the Charterers’ expense. Unless the Owners elect to waive this requirement or enter into an alternative agreement with the Charterers the Vessel shall be returned to its condition prior to the commencement of the Charter Party at the Charterers’ expense before redelivery.\n(c) Ballast Warranty\nThe Owners warrant that the Vessel is capable of operating under this Charter Party in ballast without requiring any solid ballast and using fuel and water ballast only.\n(d) Weather Routing\nThe Charterers may supply the Master with weather routing information during the currency of this Charter Party. In this event the Master shall comply with the reporting procedure of the Charterers’ weather routing service.\n(e) Communications Facilities\nThe Owners shall permit the Charterers use of the Vessel’s communication facilities at cost during the currency of this Charter Party.\n(f) Logs and Witnesses\nThe Owners shall maintain full deck, engine room and, where appropriate, refrigeration logs during the currency of this Charter Party and the Charterers or supercargo shall have full access to all the Vessel’s logs, rough and official, covering this period. The Owners undertake to produce all such documentation promptly upon request of the Charterers.\nThe Owners also undertake to endeavour to assist the Charterers by producing or assisting the Charterers to trace the Vessel’s witnesses as may be requested by the Charterers to give testimony in connection with matters arising in relation to this Charter Party and such expenses as may be incurred shall be for the Charterers’ account.\n(g) Replacement of Master and Officers\nIf the Charterers shall have reason to be dissatisfied with the conduct of the Master or Officers, the Owners shall, on receiving particulars of the complaint, investigate same and, if confirmed, replace the offending party(ies) at the Owners’ expense.\n(h) Supercargo\nThe Owners shall provide and maintain a clean and adequate room for the Charterers’ supercargo if any, furnished to the same standard as officers’ accommodation. Supercargo shall be victualled with the Vessel’s officers. The Charterers shall pay for accommodation and victualling of any supercargo at the daily rate as indicated in Box 28. Prior boarding the vessel the supercargo to sign owners’ standard L.O.I.\n(i) Victualling\nThe Owners, when requested and authorized by the Charterers or their agents, shall victual other officials and servants of the Charterers at the rate per person per meal as indicated in Box 29.\n(k) Sub-Letting\nThe Charterers shall have the right to sub-let all or part of the Vessel with the prior consent of the Owners, which shall not be unreasonably withheld, whilst still remaining responsible to the Owners for the performance of this Charter Party.\n(l) Inspections\nThe Owners shall co-operate with the Charterers to facilitate the Charterers’ inspection of the Vessel at any time, upon receipt of reasonable notice, in the Charterers’ time.\n(m) Substitution and Sub-Contracting\nUnless the Charterers’ prior consent be obtained in writing, which shall not be unreasonably withheld, the Owners may not:\n(i) substitute any other vessel for that named herein, even though it might be of identical specification, before, at the beginning of or throughout the currency of this Charter Party, or\n(ii) sub-contract any of their obligations including the management of the Vessel. In the event of any sub-contracting the Owners shall remain responsible for the performance of this Charter Party, or\n(iii) change the flag of the Vessel.\n(n) Laid-Up Returns\nThe Charterers shall have the right to order the laying-up of the Vessel at any time and for any period of time at a safe berth or place and in the event of such laying-up the Owners shall promptly take steps to effect all the economies in operation costs, including insurance, which may be possible and give prompt credit to the Charterers in respect of all such economies. At the request of the Charterers, the Owners shall at any time provide an estimate of the economies which would be possible in the event of the laying-up of the Vessel.\nThe laying-up port or place shall be at the Charterers’ option but shall always be safe and acceptable to the Owners’ insurers. Should the Charterers in liaison with the Owners decide that the Master, Officers and crew should be paid off, then the cost of repatriation and, later, cost of rejoining, including laying-up preparation and reactivation cost, and all expenses incurred shall be for the Charterers’ account.\nThe Charterers shall give sufficient notice of their intention in this respect to enable the Owners to make necessary arrangements for decommissioning and recommissioning.\nAny returns of premium or calls payable to the Owners by reason of the Vessel remaining within the confines of any port area in excess of any minimum period provided for in the Owners’ insurance policies shall be remitted to the Charterers upon receipt by the Owners, provided the Vessel was on hire for the full period, otherwise such return shall be shared pro rata between the Owners and the Charterers according to the proportion of qualifying time on and off hire.\n(o) Signing Bills of Lading\nIf required, the Master shall sign bills of lading as presented by the Charterers. If required, the Charterers and/or their agents are hereby authorized by the Owners to sign bills of lading on the Owners’ and/or the Master’s behalf (See Clause 16(a), (b) and (c)). The Charterers shall indemnify the Owners and the Master against all consequences or liabilities arising therefrom.",
    zh:"【船舶文件】船東應租家要求提供英文版文件，包括：總布置圖、容積計劃、貨櫃積載計劃、甲板及艙內貨櫃綁紮計劃（須Class批准）、縱傾及穩性手冊、靜水力曲線、裝載比例尺、艙容計劃，及其他安全有效操作所需文件，還船時歸還。【船旗/煙囪/船名/配置】租家可懸掛自己的旗幟、塗裝煙囪、更改船名（需當局批准）、改變貨櫃積載配置，一切費用由租家承擔，還船前恢復原狀（除非船東同意免除，否則按雙方協議在Owners時間及費用恢復）。【壓艙保證】船東保證船舶在空載情況下，只需燃油及水壓艙，無須固體壓艙物即可運作。【天氣路由】租家可提供天氣路由資訊，船長須遵守報告程序。【通訊設施】船東允許租家在整個租期按成本使用船舶通訊設施。【日誌及見證】船東維護完整的航海/輪機/冷凍日誌，租家（含監貨員）可全面查閱，船東協助追蹤證人出庭（費用由租家承擔）。【船長/船員更換】如租家對船長/船員表現不滿，船東在收到詳細投訴後調查，確認屬實則自費更換。【監貨員】船東提供相當於高級船員標準的住宿，租家依Box 28日費支付食宿，監貨員上船前須簽署船東標準LOI。【招待膳食】應租家授權，船東為其他租家人員提供膳食，費用依Box 29每餐每人費率計算。【轉租】在船東事先書面同意下（不得無理拒絕），租家可轉租全部或部分船舶，但對船東仍負全責。【查船】船東配合租家在合理通知後（租家時間）查驗船舶。【替換/轉包】未經租家書面同意，船東不得替換船舶、轉包任何義務或更改船旗。【停租備用】租家有權隨時讓船舶停租備用（須在安全地點，保險公司接受），船東立即採取節約運營成本措施（含保險），並將節約金額返還租家。若租家/船東決定遣散船員，所有相關遣散、再加入費用由租家承擔；保險返還按on-hire/off-hire比例分配。【提單簽發】如需要，船長按租家提示簽發提單，或租家/代理有權代船東/船長簽發提單，租家對由此產生的一切後果給予賠償。", owner:["Furnish vessel plans and documents to Charterers on request"], charterer:["Pay costs of any changes to flag, funnel, name, configuration", "Restore vessel to original configuration before redelivery"] },

  { no:"BT-14", label:"Cl.14", title:"Owners' Requirements", topic:["maintenance", "bl", "ga"],
    en:"(a) Maintenance: The Owners shall have the right to take the Vessel out of service for emergency repairs at any time and for routine maintenance by prior arrangement with the Charterers. The Owners shall endeavour to accommodate the Charterers' requirements in determining the timing of such maintenance and the Charterers shall endeavour to accommodate the Owners' choice of location for maintenance (See Clause 8(a)(i)).\n(b) Bills of Lading (to be issued in Charterers' form): The Charterers warrant that bills of lading issued in respect of the carriage of goods and containers under this Charter Party shall contain the following clauses:\n(i) A clause paramount applying the Hague or Hague-Visby Rules or a carriage of goods by sea statute making either of these mandatorily applicable, in either case according to the practice prevalent at the port(s) of loading.\n(ii) A \"New Jason\" clause.\n(iii) A \"General Average\" clause providing for adjustment at a port or place at the option of the Carrier according to the York-Antwerp Rules 1974 or any amendment thereto.\n(iv) A \"Himalaya\" or \"Circular Indemnity\" clause giving the Owners the benefit of the bill of lading terms and conditions and/or protection from tortious claims by third parties.\n(v) A \"Sister Ship Salvage\" clause.\n(vi) A \"Both-to-Blame Collision\" clause.\n(c) General Average: General average shall be adjusted at the place as indicated in Box 33 according to the York-Antwerp Rules 1974 or any amendment thereto by an adjuster appointed by the Owners. In the event of general average or salvage, the Charterers shall provide an acceptable temporary security covering all goods and containers to avoid delay and secure their release so that transit/delivery may continue. The Owners agree that the Charterers' temporary guarantee may be exchanged in due course for a full set of securities from the appropriate interested parties covering all goods and containers. The Charterers agree to co-operate with the Owners and the Owners' appointed adjusters, to assist by supplying manifest and other information and, where required, to endeavour to secure the assistance of the Charterers' local agents in the collection of security, at the Owners' expense.\nAll goods and containers shall contribute in general average, whether shipped on or under deck. Charter hire shall not contribute.\nGeneral average shall be adjusted in any currency at the sole option of the Owners. Exchange into the currency of adjustments shall be calculated at the rate prevailing on the date of payment for disbursements and on the date of completion of discharge of the Vessel for allowances, contributory value, etc. The Owners shall not declare General Average when the amount of General Average is estimated not to exceed USD 1,000,000.\n(d) Salvage: All time lost and all legal and other expenses (excluding any damage to the Vessel) incurred in saving or attempting to save life or property shall be borne equally by the Owners and the Charterers. All salvage and proceeds from derelicts shall be divided equally between the Owners and the Charterers after deducting the Master's, Officers' and crew's share. The Charterers shall be bound by all measures taken by the Owners in order to secure payment of salvage and to settle its amount.\n(e) Liens: The Charterers warrant that they will not suffer, nor permit to be continued, any lien or encumbrance incurred by them or their agents, which might have priority over the title and interest of the Owners in the Vessel. In no event shall the Charterers procure, nor permit to be procured, for the Vessel any supplies, necessaries or services without previously obtaining a statement, signed by an authorized representative of the furnisher thereof, acknowledging that such supplies, necessaries or services are being furnished on the credit of the Charterers and not on the credit of the Vessel or of the Owners and that the furnisher claims no maritime lien on the Vessel therefore.\nThe Owners shall have a lien on the Charterers' goods and containers and upon all sub-freights and/or sub-hire for unpaid charter hire, unreimbursed Charterers' expenses initially paid by the Owners and contributions in general average properly due.", zh:"【船東維修權】船東有權隨時為緊急修理讓船舶停止服務，日常維護須與租家預先安排，雙方應盡量配合對方的時間和地點偏好。【提單要求】租家保證所有提單包含以下條款：(i)適用海牙或海牙-維斯比規則的Clause Paramount；(ii)New Jason Clause；(iii)按York-Antwerp Rules 1974（或任何修訂版）在承運人選擇的港口進行共同海損調整的GA Clause；(iv)Himalaya/Circular Indemnity Clause；(v)Sister Ship Salvage Clause；(vi)Both-to-Blame Collision Clause。【共同海損】在Box 33所示地點按York-Antwerp Rules 1974（或修訂版）由船東指定的理算師調整。租家須提供暫時擔保以避免延誤，並配合船東及理算師。所有貨物及貨櫃（甲板/艙內）均須分攤共同海損，hire不分攤。可按船東選擇以任何貨幣調整；exchange rate以支付日期（費用）及卸貨完成日（責任/貢獻值）為準。船東不在GA估計不超過USD 1,000,000時宣布共同海損。【救助】船舶救助或被救助的時間損失及所有費用（不含船舶損壞）由雙方平均分擔；救助款項扣除船長/船員份額後亦平均分配。租家受船東為收取救助費及確定金額所採取的一切措施約束。【留置權】租家保證不允許因其或代理人引起的任何留置權或負擔優先於船東對船舶的所有權。租家在為船舶採購任何物品前，須取得供應商書面聲明確認係基於租家信用、不主張海事留置權。船東對租家的貨物、貨櫃、sub-freight/sub-hire有留置權，以擔保未付hire、未補償費用及共同海損貢獻。", owner:[], charterer:["Ensure B/Ls contain Clause Paramount, Jason, GA and Both-to-Blame clauses", "Provide security to avoid GA delays"] },

  { no:"BT-15", label:"Cl.15", title:"Sundry Matters", topic:["crew", "survey"],
    en:"(a) Pilotage/Towage: Although engaged by the Charterers or their agents and paid by the Charterers, all pilotage, towage and other such services to the Vessel to assist with navigation shall be engaged as agents of the Owners who, for the purposes of this Charter Party, shall remain responsible for the due performance thereof. Nothing contained in this Charter Party shall be construed as a demise of the Vessel to the Charterers and the Owners remain responsible for the navigation thereof at all times.\n(b) Watchmen: The cost of compulsory shore gangway watchmen shall be borne equally between the Owners and the Charterers throughout the currency of this Charter Party. See Clause 27.\n(c) Stowaways: Any costs incurred in respect of stowaways shall be for the Owners’ account, unless it can be established that the means by which the stowaway gained access to the Vessel was by secreting away in the Charterers’ goods and containers prior to loading, in which case all such costs shall be for the Charterers’ account.\n(d) On/Off Hire Surveys: Joint on and off hire surveys shall be conducted by mutually acceptable surveyors at the Places of Delivery and Redelivery, respectively. The on hire survey shall be conducted in the Owners’ time unless the Vessel has commenced loading. The off hire survey shall be conducted in the Charterers’ time. Surveying expense to be equally shared by Owners and Charterers.\nBoth surveys shall cover condition of the Vessel and amounts of fuel, diesel oil, galley fuel and fresh water on board and the Owners shall procure that the Master, Chief Engineer, Officers and crew shall co-operate with the surveyors in conducting such surveys.\n(e) Sub-Contractors: In this Charter Party the term “sub-contractor” shall include sub-contractors and their respective servants, agents and sub-contractors.\"sub-contractor", zh:"【領港/拖輪/服務】雖由租家安排及支付，但所有領港、拖輪及其他航行輔助服務均以船東代理人身份進行，船東對其妥善執行仍負責任。本合約不構成船舶光船租賃，船東在任何時候仍對航行負責。【守衛】強制性的岸邊通道守衛費用由Owners/Charterers平均分攤，詳見Rider Cl.27。【偷渡者】偷渡者費用原則上由船東承擔，除非可以證明偷渡者是藏匿在租家的貨物或貨櫃中上船，在此情況下所有費用由租家承擔。【交還船驗船】在交船地點（Owners時間）及還船地點（Charterers時間）分別進行雙方可接受的驗船師聯合驗船；驗船費用平攤。驗船內容涵蓋船況及船上燃油、柴油、廚房燃料及淡水數量，船東確保船長/大管輪/船員配合驗船師。【轉包商】本合約中「轉包商」包括轉包商及其各自的受僱人、代理及下級轉包商。", owner:["Share cost of on/off hire surveys equally"], charterer:["Pay pilotage and towage costs", "Share cost of compulsory shore watchmen equally", "Pay cost of stowaways who hid in Charterers' cargo"] },

  { no:"BT-16", label:"Cl.16", title:"Charterers' Responsibilities / Liabilities", topic:["cargo", "claim", "legal"],
    en:"(a) Charterers’ Responsibilities: Except as elsewhere provided in this Charter Party and without prejudice to the Charterers’ right to initiate recovery against the Owners under Clause 17, the Charterers shall be responsible for all claims in respect of any liability or expense whatsoever or howsoever arising in connection with the goods and containers carried pursuant to this Charter Party or their carriage (even if such liability arises wholly or in part by reason of the act, neglect or default of the Owners or of such servant, agent or sub-contractor).\n(b) Claims Handling: If any such claim or allegation as described in Clause 16(a) shall be made against the Owners or against any vessel owned by any of them, the Charterers will:\n(i) take over the conduct and defence of such claim or allegation and settle same at their own expense obtaining, where appropriate, releases in joint names, or, should the Owners so request,\n(ii) put the Owners in funds to meet legal fees, witness and third party expenses and settlement funds, excluding the Owners’ own office expenses, to deal with such claim or allegation themselves.\n(c) General Indemnity: If in spite of Clause 16(a) any claims as therein described are nevertheless made, the Charterers shall indemnify the Owners and such servant, agent or sub-contractor against all consequences whatsoever thereof, without prejudice to the Charterers’ right subsequently to initiate action against the Owners.\n(d) Fines etc./Indemnity: The Charterers shall indemnify the Owners against any expenses, fines, liabilities, losses, damages, claims or damages which the Owners may incur or suffer by reason of any failure of the goods or containers or the documentation relating thereto to comply with any relevant laws, regulations, directions or notices of customs, port and other authorities, or by reasons of any infestation, contamination or condemnation of goods or containers or infestation, damage or contamination of the Vessel by the Charterers’ goods or containers.\n(e) Time Limit: The Charterers shall be discharged from all liability under this Charter Party unless notice of arbitration in accordance with Clause 20 is given within 15 months of redelivery.\n(f) Agency: Without prejudice to sub-clause 16(a) the Owners authorize and empower the Charterers to act as the Owners’ agents and/or trustees to stipulate for the Owners to have as against other persons the benefit of any immunities, exemptions or liberties regarding the goods and containers the subject of this Charter Party or their carriage but the Charterers shall have no authority to make any contracts imposing any obligations upon the Owners in connection with the goods and containers or their carriage.\n(g) General Average Exclusion: Nothing in this Clause 16 shall apply to preclude any claim made by the Owners of any property on board the Vessel for general average contribution in accordance with the York-Antwerp Rules 1974 or any amendment thereto.\n(h) Claims Authority: The Charterers shall make no payment in excess of the amount as stated in Box 32 in settlement of a claim for which they intend to seek recovery from the Owners without prior consultation with the Owners. The Owners authorize the Charterers to grant extensions of time in respect of such claims provided the Charterers give the Owners immediate notice thereof.",
    zh:"【租家責任範圍】除合約另有規定外，租家對所有與貨物/貨櫃及其運輸有關的索賠、責任或費用負責，即使該責任全部或部分源於船東或其受僱人/代理/轉包商的行為、疏忽或過失，但不影響租家依Cl.17向船東追償的權利。【索賠處理】如有上述索賠或指控針對船東或任何船東船舶，租家將：(i)接管索賠的處理及抗辯，自費取得各方聯合解除責任，或應船東要求；(ii)提供資金給船東應對法律費用、證人費及和解費用（不含船東自己的辦公費用）。【一般賠償】如上述索賠仍被針對船東，租家應賠償船東及其受僱人/代理/轉包商的一切後果，不影響租家事後向船東追償的權利。【罰款賠償】租家應賠償船東因貨物/貨櫃或其文件不符合相關法規、或因租家貨物的污染/侵害造成船舶污染/損害而遭受的任何費用、罰款、損失或索賠。【時效】租家須在還船後15個月內提交仲裁通知，否則所有索賠時效消滅。【代理授權】不影響Cl.16(a)，船東授權並賦予租家代表船東爭取對抗第三方的免責/豁免/自由，但租家無權代表船東簽訂任何合約。【共同海損排除】本條款不限制船東就船上財產提出共同海損貢獻的請求。【索賠授權上限】租家對計劃向船東追償的索賠，不得在未事先與船東協商的情況下超過Box 32金額進行和解；船東授權租家在立即通知船東的前提下給予時效延長。", owner:[], charterer:["Responsible for all claims re goods/containers even if caused by Owners", "Take over conduct and defence of claims", "Fund Owners to meet legal fees and settlement costs"] },

  { no:"BT-17", label:"Cl.17", title:"Owners' Responsibilities / Liabilities", topic:["cargo", "claim", "legal"],
    en:"Except as elsewhere provided in this Charter Party, the responsibilities and liabilities of the Owners shall be as follows:\n(a) For Goods and Containers: The Owners shall be liable for loss, damage or expense in respect of goods and containers arising or resulting from:-\n(i) lack of due diligence on their part before and at the beginning of each voyage to make the Vessel seaworthy and to properly man, equip and supply it and make all parts of the Vessel in which goods and containers are carried fit and safe for their reception, carriage and preservation, unless the Charterers consent to load containers in parts of the Vessel which the Master considers to be unfit, in which case the Charterers shall indemnify the Owners.\n(ii) failure on their part properly and carefully to carry, keep and care for the goods and containers while on board, or\n(iii) unreasonable deviation from the voyage ordered or approved by the Charterers.\n(b) For Refrigerated Goods: In respect of blown-air containers, the Owners shall be responsible only to maintain the supply of air at the required temperature to the containers, provided proper instructions are given to the Master by the Charterers and the containers are presented at the carriage temperatures.\nIn respect of integral refrigerated containers or blown-air containers with a marine refrigeration clip-on unit attached or any containers with any machinery for temperature/atmosphere control containing goods, the Owners shall be responsible for the provision of electrical power only. The Owners shall endeavour to monitor and record the performance of all such units whilst on board in accordance with the Charterers’ instructions and to repair and rectify any breakdown, fault or deficiency which may occur in respect of such units using the resources on board the Vessel. If repair works are performed, all additional expenses incurred by the Owners, including spare parts, shall be for the account of the Charterers and the Vessel’s crew shall always be considered the Charterers servants. If such resources are insufficient, the Owners shall immediately notify the Charterers so they may take action to obtain any required spares or specialized repair facilities.\nExcept as provided above, the Owners shall not be liable for malfunctioning of integral refrigerated containers and power packs put on board by the Charterers.\nThe Owners shall be entitled to reject and require the Charterers to discharge any container loaded at a temperature not within the required carriage temperature range. If, at the Charterers’ request, the Owners consent to receive and carry such containers, the Charterers shall indemnify the Owners against all consequences hereof.\n(c) Limitation of Liability: The liability of the Owners to the Charterers for loss, damage or expense in respect of goods and containers as herein provided shall be limited as follows:\n(i) In respect of goods liability shall be on the same basis as applicable under mandatory law between the Charterers and a third party by reason of the Charterers having issued a bill of lading or similar contract of carriage, provided that such Bill of Lading contains no declaration of value. Where no mandatory law so applies, liability shall be limited to GB Pounds 100 per package.\n(ii) In respect of containers, liability shall be the reasonable cost of repair or the value of the container at the time of such loss or damage, whichever is the lesser. The value of a leased container is the value stated in the lease agreement and for an owned container it is its market value. For the purpose of this Charter Party containers not owned or leased by the Charterers shall be regarded as goods for liability purposes.\n(d) Time limit: Except as provided in Clause 16(h), the Owners shall be discharged from all liability under this Charter Party in respect of claims for which extensions of time have not been sought and obtained by the Charterers unless notice of arbitration in accordance with Clause 20 is given within 15 months of the delivery of goods, if the claim relates to goods, or the date when the Charterers become aware of the incident giving rise to the claim for all other claims.\n(e) For Personal Injury: The Owners shall indemnify the Charterers against any claims for personal injury incurred on or about the Vessel unless caused by the negligence of the Charterers, their servants, agents or sub-contractors or any defect in the Charterers’ goods and/or containers.\n(f) Limitation Proceedings: The Owners shall have the control and conduct of any limitation proceedings on the joint behalf of the Owners and the Charterers. If successful, any unrecovered costs of such proceedings shall be borne equally between the Owners and the Charterers. If unsuccessful, the costs shall be borne by the party responsible under the terms of this Charter Party for the factor which caused the proceedings to fail. If more than one factor contributed and the Owners and the Charterers were each responsible for at least one factor the costs shall be borne equally.\n(g) Consequential Loss: Under no circumstances shall the Owners be responsible for any indirect or consequential loss arising from loss, damage or delay to goods and containers, howsoever caused.",
    zh:"【貨物/貨櫃損失責任】船東對以下原因造成的貨損負責：(i)每次航次開始前及開始時未盡職責使船舶適航，包括妥善配員、裝備、補給，並使所有裝載貨物的艙室適合接收、運輸及保管（除非租家同意在船長認為不適合的艙室裝貨，則由租家提供賠償）；(ii)未妥善謹慎地在船上裝載、保管及照料貨物；(iii)不合理偏離租家訂定或批准的航線。【冷凍貨物責任】吹氣式冷凍貨櫃：船東只負責以所需溫度向貨櫃供氣（前提是租家提供正確指示且貨櫃以運輸溫度交付）。帶有獨立製冷設備的貨櫃：船東只負責提供電力，並依租家指示監測記錄，修復任何故障（費用由租家承擔，船員視為租家受僱人）；若板上資源不足，應立即通知租家。除上述規定外，船東對租家放置的整體式冷凍貨櫃及電力機組的故障不負責任。船東有權拒絕並要求卸下溫度不在規定範圍內的貨櫃；若應租家請求同意裝運，租家賠償一切後果。【賠償限額】(i)貨物：按適用法律（Charterers對第三方提單的強制性義務）計算，無法律規定時上限為每件英鎊100；(ii)貨櫃：合理修復費或滅失/損壞時的市值（取低），租賃貨櫃按租約所示價值，自有貨櫃按市值；非租家所有或租賃的貨櫃視為貨物處理。【時效】船東對租家的索賠，若租家未事先爭取時效延長，則在貨物交付後15個月內（貨物索賠）或租家知悉事件日後15個月內（其他索賠）若未提交仲裁通知，時效消滅。【人身傷害】船東對船舶上或附近發生的人身傷害索賠提供賠償，除非係由租家/其受僱人/代理/轉包商的疏忽或租家貨物/貨櫃缺陷引起。【訴訟/限制程序】船東掌控並主導代表雙方的責任限制程序，費用由造成程序失敗的一方承擔，若雙方均有責任則平均承擔。【間接損失免責】任何情況下船東不對貨物/貨櫃的間接或後果性損失負責。", owner:["Liable for cargo loss due to lack of due diligence at beginning of voyage", "Liable for failure to properly carry and care for goods", "Liable for unreasonable deviation"], charterer:[] },

  { no:"BT-18", label:"Cl.18", title:"Insurances", topic:["insurance"],
    en:"(a) Hull and Machinery: The Owners warrant that the Vessel is insured under Institute Time Clauses or similar Clauses for IWL trading against loss, damage and collision liabilities for the value as indicated in Box 27 which cover will be maintained throughout the currency of this Charter Party. Upon 10 days notice to the Charterers, the Owners shall be entitled to effect any reasonable change to this value. The Owners agree that their insured value for the purpose of this Clause shall represent the Charterers maximum liability to the Owners for damage to the Vessel in accordance with Clause 6 (l), including time spent on repairs.\n(b) Protection and Indemnity (P & I): The Owners and the Charterers warrant that the Vessel is entered on full terms with their respective P & I Clubs as indicated in Boxes 30 and 31 and that such entries will be maintained with all calls paid up to date throughout the currency of this Charter Party.\n(c) War Risks: The Owners warrant that the Vessel is insured against loss of the Vessel by War Risks and War P & I Risks for IWL trading excluding additional premium/restricted/prohibited areas, which cover will be maintained throughout the currency of this Charter Party.",
    zh:"【未經同意禁止事項】未獲船東書面同意，船舶不得：(i)停留或通過因戰爭/敵對行動/海盜/恐怖主義（實際或威脅）而危險或可能危險的區域；(ii)掛靠有革命/內戰/騷亂或其威脅的港口；(iii)運載可能導致船舶被扣押、捕獲或拘留的任何貨物。【船東同意進入的後果】如船東同意，則視為船東自行承擔風險進入，作為補償，船東有權安排以下保險，費用由租家在下次hire支付時補償：(i)H＆M及P＆I的戰爭風險復效保費；(ii)被封鎖/困住期間維持Hull保險所需的額外保費（直至CTL確認或累積365天）；(iii)不超過365天的租金保險。【特殊費用增加】如因上述因素導致船長/船員工資或其他運營費用增加，由租家在下次hire支付時補償。【政府指令自由】船舶有自由遵守任何政府（船旗國或其他）或有權限人士的命令，或遵守戰爭風險保險人或聯合國的指令；依此所做的任何事項均不構成偏航。【合約解除】如以下國家之間（或涉及船旗國）爆發戰爭（無論是否宣戰）：中華人民共和國、法國、德意志聯邦共和國、美利堅合眾國、英國、蘇聯，則任何一方均可取消合約，還船在卸完貨物後在目的港或最近的安全開放港進行，依本條款採取的任何行動均不構成偏航。", owner:["Maintain H&M insurance for value in Box 27 throughout charter", "Maintain P&I insurance throughout charter", "Maintain War Risks insurance throughout charter"], charterer:[] },

  { no:"BT-19", label:"Cl.19", title:"War", topic:["war"],
    en:"(a) Unless the consent of the Owners be first obtained, the Vessel shall not be ordered to nor obliged to:-\n(i) remain in or pass through any area which is dangerous or is likely to become dangerous as a result of war, hostilities, warlike action or piracy, actual or threatened, nor\n(ii) call at any port where there is any revolution, civil war, civil commotion or any threat thereof, nor\n(iii) carry any goods that may in any way expose her to any risk of seizure, capture or detention.\n(b) However, should the Owners consent to allowing the Vessel to proceed, notwithstanding the existence or threat of the danger(s) outlined in Clause 19(a), the Owners agree that the Vessel proceeds at their own risk in consideration of the Charterers agreeing that the Owners may effect the following insurances for which the Charterers will reimburse the Owners the net cost of premium/calls therefore: (See Clause 6(n))\n(i) Reinstatement of the War Risks cover on Hull and P & I for trading to the required area.\n(ii) Any further additional premia necessary to maintain Hull cover whilst blocked or trapped pending release of the Vessel, acceptance of constructive total loss by insurers or trapped for 365 consecutive days, whichever shall first occur.\n(iii) Insurance of hire on the Vessel for not exceeding 365 days.\n(c) In the event of the wages of the Master, Officers and/or crew and/or other of the Vessel’s operating expenses are affected by any of the factors mentioned in (a) above, the amount of any increase shall be added to the hire due upon production of the Owners’ account therefore together with appropriate receipts and paid by the Charterers to the Owners with the next hire payment.\n(d) The Vessel shall have the liberty to comply with any orders or directions of whatsoever nature given by the government of the nation where the Owners are domiciled or whose flag the Vessel flies or any other government or person or body acting, or purporting to act, with the authority of such government or by any party having, under the terms of the war risk insurance on the Vessel, the right to give such orders or directions.\n(e) In the event of the outbreak of war, whether there be a declaration of war or not, between any two or more of the following countries or involving the nation where the Owners are domiciled or whose flag the Vessel flies:- People’s Republic of China, France, Federal Republic of Germany, United States of America, United Kingdom, Union of Soviet Socialist Republics, either the Owners or the Charterers may cancel this Charter Party and, unless otherwise agreed, the Vessel shall be redelivered to the Owners at the port of destination or, if debarred under this Clause from reaching or entering it, at a near open and safe port at the Owners’ option after discharge of any goods and containers on board.\n(f) If in compliance with the provisions of this Clause anything is done or is not done, such shall not be deemed a deviation.",
    zh:"【適用法律及仲裁地】依Box 34選擇：(a)倫敦仲裁，適用英國法律及Arbitration Acts 1950/1979；收到對方仲裁員提名後14天內各自指定仲裁員，逾期則由單一仲裁員裁決；兩位仲裁員意見不一致時指定裁判員，其裁決為終局。(b)紐約仲裁，三人組成，依Society of Maritime Arbitrators, Inc.規則進行。(c)其他：依Box 34所示地點及適用法律/程序進行仲裁。若Box 34空白，自動適用(a)倫敦仲裁。", owner:[], charterer:["Pay additional war risk insurance premiums if Owners consent to proceed", "Pay increased wages arising from war risk areas"] },

  { no:"BT-20", label:"Cl.20", title:"Law and Arbitration", topic:["legal"],
    en:"*) (a) London: This Charter Party shall be governed by English law and any dispute arising out of this Charter Party shall be referred to arbitration in London, one arbitrator being appointed by each party, in accordance with the Arbitration Acts 1950 and 1979 or any statutory modification or re-enactment thereof the time being in force. On the receipt by one party of the nomination in writing of the other party’s arbitrator, that party shall appoint their arbitrator within fourteen days, failing which the decision of the single Arbitrator appointed shall apply. If two Arbitrators properly appointed shall not agree they shall appoint an umpire whose decision shall be final.\n*) (b) New York: Should any dispute arise out of this Charter Party, the matter in dispute shall be referred to three persons in New York, one to be appointed by each of the parties hereto, and the third by the two so chosen; their decision or that of any two of them shall be final, and for the purpose of enforcing any award, this agreement may be made a rule of the Court. The arbitrators shall be members of the Society of Maritime Arbitrators, Inc. of New York and the proceedings shall be conducted in accordance with the rules of the Society.\n*) (c) Alternative: Any dispute arising out of this Charter Party shall be referred to arbitration at the place indicated in Box 34, subject to the law and procedures applicable there.\nIf Box 34 in Part I is not filled in, sub-clause (a) of this Clause shall apply.",
    zh:"【佣金支付】船東依Box 35所示費率向Box 35所示掮客支付佣金，以本合約支付的所有hire為計算基礎，但最低須足以彌補掮客的實際費用。若因任何一方違約導致全額hire未能支付，違約方須對掮客的佣金損失負責。若雙方同意取消本合約，船東須補償掮客的佣金損失，但不超過一年hire的佣金金額。", owner:[], charterer:[] },

  { no:"BT-21", label:"Cl.21", title:"Commission", topic:["legal"],
    en:"The Owners shall pay a commission at the rate stated in Box 35 to the party mentioned in Box 35 on any hire paid under this Charter Party but in no case less than is necessary to cover the actual expenses of the Brokers. If the full hire is not paid owing to breach of Charter Party by either of the parties the party liable therefore shall indemnify the Brokers against their loss of commission.\nShould the parties agree to cancel this Charter Party, the Owners shall indemnify the Brokers against any loss of commission but in such case the commission shall not exceed the brokerage on one year’s hire.",
    zh:"【通知義務】對船東的通知送至Part I所示地址（V.Ships Hamburg，透過Blue Net Chartering）；對租家的通知送至Box 4所示地址。", owner:["Pay brokerage commission per Box 35"], charterer:[] },

  { no:"BT-22", label:"Cl.22", title:"Notices", topic:["legal"],
    en:"Any notice to the Owners shall be sent to………………………………………………\nAny notice to the Charterers shall be sent to the address as indicated in Box 4.",
    zh:"【通知義務】對船東的通知送至Part I所示地址；對租家的通知送至Box 4所示地址。", owner:[], charterer:[] },

];

const RIDERS_BASE = [
  { no:"R-23", label:"Cl.23", title:"Stowage", topic:["cargo","stowage"], en:"Planning of container or out of gauge containerized stowage on board to be done by port planners or to be assisted by charterers or the vessel if requested by charterers. A reasonable amount of out of gauge containerized cargo may be carried on deck/hatches and in holds lashed but within capacity, stability of vessel, strength on deck/hatch covers and Master's satisfactory of lashing, stowage etc.", zh:"【OOG貨物積載規劃】超大型貨物（Out of Gauge）的積載規劃由港口計劃師負責，如有需要可請租家或船舶協助。合理數量的OOG貨物可裝在甲板、艙蓋上或艙內並加以綁紮，但必須在船舶的容量、穩定性、甲板/艙蓋強度限制內，且須經船長對綁紮及積載方式確認滿意。", owner:[], charterer:[] },
  { no:"R-24", label:"Cl.24", title:"Lashing Materials, Victualling & Communication", topic:["cost","lashing"], en:"Charterers to pay lumpsum USD 1,600 per month pro rata for lashing material compensation and communication/entertainment/victualling expenses for the whole duration of charter party and without changes.", zh:"【固定費用包幹】租家每月按比例支付USD 1,600固定費用，涵蓋：(1)綁固材料補償費用；(2)船員通訊費用；(3)船員娛樂費用；(4)船員膳食費用。此費率在整個租期固定不變，不因任何原因調整。", owner:[], charterer:["USD 1,600/month (fixed, pro rata)"] },
  { no:"R-25", label:"Cl.25", title:"Quarantine", topic:["cost","crew"], en:"Normal quarantine time and expenses to enter the port to be for Charterers' account. Any time of detention and expense for quarantine due to pestilence, illness etc. of Master/officers and crew to be for Owners' account.", zh:"【正常入港檢疫費用→租家】正常的入港檢疫時間及費用由租家承擔，屬於租家的日常港口運營成本。【因船員健康原因的額外檢疫→船東】若因船長、船員感染疾病、疫情或類似健康原因，導致船舶被特別拘留或需要額外的隔離時間，所有額外時間損失及費用均由船東承擔，此期間視為off-hire。", owner:["Quarantine due to crew illness/pestilence"], charterer:["Normal port quarantine expenses"] },
  { no:"R-26", label:"Cl.26", title:"Agents", topic:["cost","crew"], en:"In case Charterers' agent attends vessel's requirements for crew transportation or delivery of vessel's spares, Charterers' agent shall charge Owners the actual cost including manpower cost and 2.5% handling fee. For major services such as major repairs, Owners to negotiate agency fee directly or appoint own agents.", zh:"【租家代理協助船東事務的費用】當租家代理為船東辦理事務（如協助船員交通、代收/交付船舶備件等），租家代理可向船東收取實際費用加2.5%的手續費。【重大服務自行處理】對於大修等重大服務，船東可直接與代理協商費用，或自行指定代理，不必透過租家代理。", owner:["Actual cost + 2.5% for using Charterers' agent"], charterer:[] },
  { no:"R-27", label:"Cl.27", title:"Watchman", topic:["cost","security"], en:"Compulsory watchman and watchman for cargo to be for Charterers' account. Non-compulsory watchman and watchman for cargo requested by the Master to be for Owners' account. Any changes arising from ISPS Code to be discussed and agreed between parties.", zh:"【強制性守衛→租家】港口法規或當局要求的強制性守衛（含貨物守衛）費用由租家承擔。【非強制性守衛→船東】船長出於謹慎或其他理由主動要求的非強制性守衛費用由船東承擔。【ISPS Code變更】因ISPS保安章程要求產生的任何費用變化，須由雙方協商確認後才能改變原有安排。", owner:["Non-compulsory watchman at Master's request"], charterer:["Compulsory watchman"] },
  { no:"R-28", label:"Cl.28", title:"Cargo Claim", topic:["cargo","claim"], en:"Liabilities for cargo claims shall be borne by Owners/Time Charterers in accordance with the Interclub New York Produce Exchange Agreement dated 1st September 1996 and all its reprints and amendments. Supplements BOXTIME Cl.17.", zh:"【Interclub Agreement應用】貨損責任依照1996年9月1日的Interclub NYPE協議（及所有後續修訂版本）在船東與時間租家之間分攤。此條款補充並明確BOXTIME Cl.17的規定，提供一個客觀的責任分攤框架，避免每次貨損都需要個別判斷責任歸屬。主要分攤原則：裝卸作業損失→租家75%/船東25%；航行過失→船東100%；兩者混合原因→依比例分攤。", owner:[], charterer:[] },
  { no:"R-29", label:"Cl.29", title:"Unauthorized Passenger / Deviations", topic:["deviation","crew"], en:"Master is bound to assist vessels in distress. Under international law the Master is bound to assist boat people/refugees as per guidelines issued by the United Nations. Should the vessel become involved in either of the above, Master/Owners will do their utmost to minimize any delay to Charterers.", zh:"【救助遇難義務】船長依法有義務救助遇難船舶，此行為不構成違約。【救助難民義務】依國際法及聯合國指引，船長有義務救助船民及難民，此類偏航亦不構成違約。【盡量減少延誤】無論是救助遇難船或難民，船長/船東都須盡最大努力減少對租家業務的延誤影響。此類情況下的時間損失通常由船東承擔（視情況可能構成off-hire）。", owner:[], charterer:[] },
  { no:"R-30", label:"Cl.30", title:"Vessel's Speed", topic:["speed","offhire","performance"], en:"If upon the voyage the speed be reduced by deficit in or breakdown of any part of the vessel's hull and machinery or equipment, the time so lost and the cost of any extra fuel consumed shall be for Owners' account and deducted from the hire. In piracy areas: Owners to guarantee vessel will maintain most economic speed and can speed up to max within 15 minutes if vessel encounters critical situation; Charterers to be informed immediately. Supplements BOXTIME Cl.9.", zh:"【機械故障減速】若因船體、機械、設備的任何部分缺陷或損壞導致航速降低，所損失的時間及多消耗的燃油費用均由船東承擔，從hire中扣除。補充BOXTIME Cl.9的速度保證條款。【海盜區域特別規定】在海盜高風險區域：船東保證船舶在節油速度下正常航行，若遇緊急情況，能在15分鐘內加速至最高船速；一旦遭遇緊急情況須立即通知租家。", owner:["Time lost and extra fuel due to breakdown"], charterer:[] },
  { no:"R-31", label:"Cl.31", title:"Bunker on Delivery / Redelivery", topic:["bunker","redelivery","delivery"], en:"Bunkers on delivery as on board. Redelivery: not less than VLSFO 400 MTs and LSMGO 50 MTs. Bunker price per Platts Oilgram mean price at port of delivery/redelivery on day of delivery/redelivery (or nearest working day). Payment for bunkers on delivery together with second hire; redelivery bunker value deducted from last sufficient hire. Modifies BOXTIME Cl.8.", zh:"【交船燃油】交船時帶上船上實有油量。【還船最低油量】還船時VLSFO（超低硫燃油）不少於400公噸，LSMGO（低硫海洋柴油）不少於50公噸，確保船舶可安全航至最近加油港。【計價方式】依交還船港口當日（或最近工作日）的Platts Oilgram均值計算。【支付時機】交船燃油款項與第二期hire一起支付；還船燃油款項從最後一期足夠的hire中扣除。此條款修改並細化BOXTIME Cl.12(a)的規定。", owner:["Pay for bunkers at redelivery"], charterer:["Pay for bunkers at delivery (with 2nd hire)"] },
  { no:"R-32", label:"Cl.32", title:"Fuel Consumed During Off-hire", topic:["bunker","offhire"], en:"Fuel used by the vessel during off-hire to be agreed as to quantity and the cost to be deducted from the hire after Charterers and Owners confirm and agree the exact time of off-hire. Supplements BOXTIME Cl.7.", zh:"【停租期間燃油處理】停租期間船舶耗用的燃油，在雙方確認並同意停租的確切時間後，就具體數量和費用達成協議，然後從hire中扣除。此條款補充BOXTIME Cl.8，確保停租期間的燃油費用不會由租家承擔（因為停租期間船舶不在為租家服務）。", owner:["Off-hire period fuel (deducted from hire)"], charterer:[] },
  { no:"R-33", label:"Cl.33", title:"[DELETED]", topic:[], deleted:true, en:"This clause has been deleted from the Charter Party.", zh:"【已刪除】本條款在本合約中已被刪除，不適用。", owner:[], charterer:[] },
  { no:"R-34", label:"Cl.34", title:"Trading Limits", topic:["trading"], en:"Charterers' worldwide service via safe port(s)/safe berth(s)/safe anchorage(s), always within I.N.L./I.W.L. Current intention (without guarantee) is Intra Asia service. Trading exclusions include: Iran, Iraq, North Korea, Syria, Somalia, Ukraine, Russia/CIS (except Vostochniy & Vladivostok), Myanmar, Yemen (except South Yemen), Libya incl. Gulf of Sidra, piracy high risk areas of the Indian Ocean/East Africa (JWC), Gulf of Aden (transit only with BMP4), and all countries subject to UN/US/EU sanctions. Calling P.R.C. and Taiwan directly (or vice versa) not allowed unless approved by both governments. Cabotage trading expressly excluded. Modifies BOXTIME Cl.2.", zh:"【全球交易範圍】租家的全球服務，須在安全港口/安全泊位/安全錨地，始終在INL/IWL（倫敦保險商保證範圍）內。現行航線計劃為亞洲區內服務（非合約保證）。【明確禁止交易的地區和國家】伊朗、伊拉克、北韓、敘利亞、索馬利亞、烏克蘭、俄羅斯/CIS（Vostochniy和Vladivostok除外）、緬甸、葉門（南葉門除外）、利比亞（含錫爾特灣）、印度洋/東非海盜高風險區（JWC）、亞丁灣（僅過境且遵守BMP4）、以及所有受聯合國/美國/歐盟制裁的國家。【中台直航限制】P.R.C.（中國大陸）與台灣之間的直接掛靠（或反向）不允許，除非獲得兩岸政府當局批准。【禁止沿海貿易】明確禁止各國境內的沿海貿易（Cabotage）。此條款修改BOXTIME Cl.3。", owner:[], charterer:[] },
  { no:"R-35", label:"Cl.35", title:"Hire Payment", topic:["hire"], en:"All hires to be remitted by telegraphic transfer from Charterers named in C/P. Banking charges outside receiving bank for Charterers' account; inside receiving bank for Owners' account. Charterers have liberty to deduct estimated redelivery bunkers and reasonable estimated outstanding disbursements. Owners to issue invoice 7 working days before hire due. Modifies BOXTIME Cl.6.", zh:"【電匯支付】所有hire由合約指定的租家以電匯方式匯款。【銀行費用分攤】收款銀行以外產生的外部銀行手續費由租家承擔（如中間行費用）；收款銀行內部費用由船東承擔（如入帳手續費）。【租家預扣權】租家有權從hire中預先扣除：(1)預計還船燃油費用；(2)合理估計的未結算費用墊款。【發票要求】船東須在hire到期日前7個工作天發出發票。此條款修改BOXTIME Cl.7(b)的支付條款。", owner:["Bank charges inside receiving bank"], charterer:["Bank charges outside receiving bank"] },
  { no:"R-36", label:"Cl.36", title:"Delivery Notice", topic:["delivery"], en:"Owners to tender 10/5 days' approximate and 3/1 days definite delivery notice. Supplements BOXTIME Cl.3.", zh:"【四層交船通知制度】船東須按以下順序發出交船通知，以便租家提前安排：第一層：提前10天的預估通知；第二層：提前5天的預估通知；第三層：提前3天的確定通知；第四層：提前1天的確定通知。此條款補充BOXTIME Cl.1(b)的交船要求，確保租家有充足時間準備接船。", owner:["Issue 4-layer delivery notice"], charterer:[] },
  { no:"R-37", label:"Cl.37", title:"Owner's Expenses", topic:["cost","crew"], en:"Owners to pay for all expenses of officers and crew including immigration fees and all consular fees necessitated because of the vessel's flag or nationality of owners. The vessel to have on board all certificates necessary to comply with current requirements at calling ports; failing which Owners are responsible for all time lost and expenses incurred.", zh:"【船員費用→船東全擔】船東負擔所有船長及船員費用，包括：正常薪資、移民手續費、領事費（凡因船旗或船東國籍需要者）。【證書完備義務】船舶須備齊在所有掛靠港口作業所需的全部有效證書；若因缺乏有效證書導致任何時間損失或費用，一切後果由船東承擔（視為off-hire）。這是船東的絕對義務，不得以任何理由免責。", owner:["All crew expenses, immigration, consular fees","Time lost due to missing certificates"], charterer:[] },
  { no:"R-38", label:"Cl.38", title:"Place of Redelivery", topic:["redelivery"], en:"Dropping last outward sea pilot, 1 safe port Kelang–Japan range, including P.R.C./Hong Kong/Taiwan/Thailand/Singapore, at Charterers' option, any time day or night, Sundays and holidays included. In case Charter Party is cancelled in accordance with the termination clause, vessel can be redelivered in Vietnam/Indonesia/Philippines. Modifies BOXTIME Cl.20.", zh:"【正常還船範圍】在租家選擇下，在以下範圍內任一安全港口（掛最後出港領港時起算），全天候（包括週日及假日）還船：吉隆坡至日本範圍，包括中國大陸、香港、台灣、泰國、新加坡。【提前解約的還船選擇】若依解約條款（Rider Cl.49）終止合約，船舶可在越南、印尼或菲律賓還船，給予租家更大彈性。此條款修改BOXTIME Cl.6(m)。", owner:[], charterer:[] },
  { no:"R-39", label:"Cl.39", title:"Insufficient Crew Members", topic:["crew","offhire"], en:"Any time lost by reasons of the full crew not being on board in time when the vessel is ready to sail, or from crew's strike, to be at Owners' account. Expenses to keep vessel waiting or cancelling tugs, pilot or mooring boats to be for Owners' account.", zh:"【船員遲到/罷工→船東全責】任何因船員未能及時到位（船舶已準備好開航時）或因船員罷工造成的時間損失，均由船東承擔（off-hire）。因此等待的費用，包括：取消拖輪、引水船、繫纜船的費用，均由船東負責。這是船東對船員管理義務的體現，船員問題不得轉嫁給租家。", owner:["All time and costs from crew absence or strike"], charterer:[] },
  { no:"R-40", label:"Cl.40", title:"Fresh Water", topic:["cost"], en:"Fresh water consumed for purpose of drinking and washing for crew on board to be for Owners' account. Fresh water used for hold cleaning and/or for Charterers' business to be for Charterers' account.", zh:"【船員生活用水→船東】船員飲用及盥洗用的淡水費用由船東承擔，屬於船員生活必需品，是船東的運營成本。【業務用水→租家】用於清艙或其他租家業務目的的淡水費用由租家承擔，因為這是租家直接需要的服務。", owner:["Crew drinking and washing water"], charterer:["Hold cleaning and business water"] },
  { no:"R-41", label:"Cl.41", title:"Crew Works", topic:["crew","cargo"], en:"Provided weather and safety of vessel permit, officers and crew to get vessel's hatches ready as much as possible prior to arrival at loading and/or discharging port so as to immediately commence loading and/or discharging cargoes.", zh:"【艙口提前準備義務】在天氣及船舶安全允許的條件下，船員須盡量在抵達裝卸港前就完成艙口準備工作，以便靠泊後立即開始裝卸作業，減少租家的等待時間。這體現了船東/船員配合租家商業運營的義務。", owner:["Prepare hatches before arrival"], charterer:[] },
  { no:"R-42", label:"Cl.42", title:"Extra Insurance", topic:["cost","insurance"], en:"Extra insurance, if any, owing to vessel's class and/or flag (if not directed by Charterers) to be for Owners' account.", zh:"【船級/船旗額外保費→船東】因船舶船級或船旗（若非由租家指定）產生的任何額外保費，由船東承擔。例如：若船旗屬於保險公司認為高風險的國家，需支付額外保費，這屬於船東的運營成本。但若係租家指定特定船旗，則另當別論。", owner:["Extra insurance due to vessel class/flag"], charterer:[] },
  { no:"R-43", label:"Cl.43", title:"Blockade / Boycott", topic:["offhire","strike"], en:"If loss of time or detention is due to boycott of the vessel by shore labourers or government restriction caused solely by vessel's flag, crew employment terms, or any previous trading of this vessel (except trading under this C/P), payment of hire shall cease from commencement until work is resumed. Owners to reimburse Charterers for expenses directly incurred from such blockade or boycott.", zh:"【因船旗/船員原因遭封鎖→船東負責】若時間損失或拘留完全因以下原因引起的碼頭工人或政府抵制：(1)船舶船旗；(2)船員僱傭條款；(3)船舶過去的交易記錄（非本合約下的交易），則從抵制開始至恢復作業期間停租。船東還須補償租家因此直接產生的費用。此條款保護租家免受船舶歷史問題的影響。", owner:["Reimburse Charterers for boycott/blockade costs"], charterer:[] },
  { no:"R-44", label:"Cl.44", title:"Lights for Night Work", topic:["cost","cargo"], en:"Vessel to provide and maintain free of expense to Charterers sufficient and efficient electric light cluster as required by local port regulations to permit simultaneous work at all hatches at the same time at night.", zh:"【夜間照明→船東免費提供】船舶須提供並維護符合所有掛靠港口法規要求的足夠高效電力照明，使所有艙口能夠同時在夜間進行裝卸作業，且此照明服務對租家完全免費。這確保了24小時不間斷的作業能力，提升運營效率。", owner:["Provide night work lighting free of charge"], charterer:[] },
  { no:"R-45", label:"Cl.45", title:"Master's Cable / Telexes", topic:["crew","communication"], en:"During voyages Master to keep Charterers and/or their agents informed of the vessel's position and expected time of arrival at next port. Charterers will separately advise Master of procedures for maintaining proper communications.", zh:"【船位報告義務→船東/船長】航程中船長須主動向租家及/或其代理報告船舶位置及預計抵達下一港的時間（ETA）。【通訊程序→租家提供】租家須另行告知船長保持適當通訊的具體程序和要求。這確保了租家對船舶動態的掌握，有助於港口作業安排。", owner:["Maintain position reporting"], charterer:["Provide communication procedures"] },
  { no:"R-46", label:"Cl.46", title:"Sludge Removal", topic:["cost","environment"], en:"Sludge removal, immigration and garbage removal, if any, to be arranged by Owners and for Owners' account.", zh:"【油泥/垃圾處理→船東全包】船東負責安排並承擔以下費用：(1)油泥清除費用；(2)移民手續相關費用；(3)垃圾清除費用。這些屬於船東維持船舶合規運營的義務，不應轉嫁給租家。", owner:["Sludge/garbage removal costs"], charterer:[] },
  { no:"R-47", label:"Cl.47", title:"Charterers' Equipment", topic:["cargo","maintenance"], en:"Master on Owners' behalf is required to sign receipt of cargo handling materials and shall be responsible for redelivery of same to Charterers or their agents prior to redelivery of vessel in like good order and condition (ordinary wear and tear excepted). Owners shall be responsible for any shortage unless caused by Charterers and/or their servants or reasons beyond Owners' control.", zh:"【租家設備管理】船長代表船東須簽收租家提供的貨物處理材料，並負責在還船前將其以同等良好狀態（正常損耗除外）歸還給租家或其代理。【短缺責任】若有短缺，除非係由租家/其受僱人引起或不可抗力原因，否則由船東負責賠償。船長/船員/船員須盡最大努力保護租家財產。", owner:["Responsible for equipment shortage (unless Charterers' fault)"], charterer:[] },
  { no:"R-48", label:"Cl.48", title:"Slow Steaming", topic:["speed","bunker"], en:"Charterers have the privilege of slow steaming the vessel at any speed acceptable to vessel's machinery and hull. See also Rider Cl.96 (BIMCO SSS Clause) for detailed slow/ultra-slow steaming provisions.", zh:"【慢速航行權利】租家有權在任何時候要求船舶以對船舶機械和船體可接受的任何速度進行慢速航行，以節省燃油或其他目的。但應注意不得損害機械或船體安全。詳細的慢速/超慢速航行規定見Rider Cl.96（BIMCO SSS Clause）。", owner:[], charterer:["Right to order slow steaming"] },
  { no:"R-49", label:"Cl.49", title:"Cancellation of Charter Party", topic:["offhire","cancellation"], en:"Should the vessel be off-hire more than 25 consecutive days (except scheduled drydocking/maintenance agreed pursuant to class requirements or mutually agreed drydocking/maintenance), Charterers shall have the option to cancel this Charter Party, provided vessel is empty. Hire paid in advance to be immediately refunded to Charterers by Owners.", zh:"【連續停租25天→租家可解約】若船舶連續停租超過25天（計畫性乾塢/維修或雙方協議的維修除外），租家有權選擇取消本合約（前提是船舶當時為空船）。取消後已預付未賺取的hire須立即退還租家。這是租家的選擇權，不是自動終止，租家可選擇繼續等待。", owner:["Immediately refund prepaid hire"], charterer:["Option to cancel after 25 consecutive off-hire days"] },
  { no:"R-50", label:"Cl.50", title:"[DELETED]", topic:[], deleted:true, en:"This clause has been deleted from the Charter Party.", zh:"【已刪除】本條款在本合約中已被刪除，不適用。", owner:[], charterer:[] },
  { no:"R-51", label:"Cl.51", title:"Vessel's Status", topic:["maintenance","offhire"], en:"If the vessel were likely to be delayed by reasons of any damage, defect, engine breakdown, or deficiency of the vessel's hull, machinery, equipment or repairs and maintenance including dry-docking, Master shall immediately notify Charterers/the Agents at next port and expected readiness.", zh:"【即時通知義務→船東】若船舶因任何損壞、缺陷、機械故障或船體/機械/設備的缺陷（包括乾塢/維修）可能造成延誤，船長須立即通知租家及/或下一港代理，並告知預計恢復正常服務的時間。及時通知讓租家能盡早安排應對方案，減少商業損失。", owner:["Immediate notification obligation"], charterer:[] },
  { no:"R-52", label:"Cl.52", title:"[DELETED]", topic:[], deleted:true, en:"This clause has been deleted from the Charter Party.", zh:"【已刪除】本條款在本合約中已被刪除，不適用。", owner:[], charterer:[] },
  { no:"R-53", label:"Cl.53", title:"Universal Time Coordinated (UTC)", topic:["delivery","redelivery"], en:"Time of delivery/redelivery to be converted to UTC (Universal Time Coordinated).", zh:"【UTC時間標準】所有交還船時間均換算為UTC（協調世界時）記錄，避免因時區差異或夏令時間造成計算爭議。確保全球業務中時間計算的一致性和準確性。", owner:[], charterer:[] },
  { no:"R-54", label:"Cl.54", title:"House-to-House Bills of Lading", topic:["bl","cargo"], en:"Charterers to keep Owners harmless for any additional expenses and/or damages to containers and/or cargo if through or house-to-house bills of lading are signed, if damages/additional expenses occur after actual discharging or prior to loading of the containers and/or cargo from/on this vessel. Supplements BOXTIME Cl.15.", zh:"【門到門提單下的租家責任】若簽發門到門（house-to-house）或通程提單，當貨物/貨櫃在以下時間段發生損壞或額外費用，租家須保持船東無損害：(1)實際從船上卸貨後的陸上運輸段；(2)在裝上船之前的陸上運輸段。此條款保護船東免受其無法控制的岸上運輸責任。補充BOXTIME Cl.14(b)。", owner:[], charterer:["Hold Owners harmless for pre-load/post-discharge damage"] },
  { no:"R-55", label:"Cl.55", title:"Container Discharge", topic:["bl","cargo"], en:"Should Charterers discharge containers or other cargoes at another port than mentioned in the bills of lading, Owners to be kept harmless for any legal consequences and/or costs arising therefrom.", zh:"【錯誤卸貨港→租家全責】若租家在提單所示港口以外的港口卸貨貨物或貨櫃，由此產生的一切法律後果及費用均由租家承擔，船東對此不承擔任何責任。這保護船東免受因租家商業安排與提單不符而引起的索賠。", owner:[], charterer:["All legal consequences of discharging at wrong port"] },
  { no:"R-56", label:"Cl.56", title:"Declared Weights", topic:["cargo","safety"], en:"Whenever possible, Charterers or their agents to furnish Master with shippers' declared gross weights for containers. Charterers to be responsible for consequences, delay and expenses created by the lack of such information and from substantial discrepancies between cargo manifest and actual container weights.", zh:"【VGM申報重量提供義務→租家】租家或其代理須盡量向船長提供托運人申報的貨物毛重（符合SOLAS VGM規定）。若因缺少重量信息或貨物艙單與實際貨櫃重量嚴重不符造成的後果、延誤及費用，均由租家負責。準確的重量信息對於積載安全至關重要。", owner:[], charterer:["Consequences of missing/incorrect weight declarations"] },
  { no:"R-57", label:"Cl.57", title:"BIMCO Non-Lien Provision", topic:["lien"], en:"Charterers will not permit any lien or encumbrance incurred by them which might have priority over Owners' interest in the vessel. Charterers shall not procure supplies for the vessel without first obtaining a signed statement from the supplier acknowledging that supplies are furnished on the credit of the Charterers, not the vessel or Owners, and that no maritime lien is claimed. Supplements BOXTIME Cl.13.", zh:"【BIMCO防留置權條款】租家保證不允許因其或代理人的行為產生任何可能優先於船東船舶所有權的留置權或負擔。關鍵要求：租家在為船舶採購任何物品/服務之前，須首先取得供應商書面聲明，確認：(1)物品係基於租家信用提供，非船舶或船東信用；(2)供應商不主張對船舶的任何海事留置權。此條款補充並強化BOXTIME Cl.14(e)。", owner:[], charterer:["Ensure supplier signs non-lien statement before supply"] },
  { no:"R-58", label:"Cl.58", title:"Illegal Merchandise Inside Sealed Containers", topic:["cargo","legal"], en:"Any unlawful and/or illegal merchandise and/or goods pertaining to the cargo found inside sealed containers are solely at Charterers' responsibility and all resulting consequences are to be borne by Charterers.", zh:"【密封貨櫃內違禁品→租家全責】若在密封貨櫃內發現任何違法/非法商品，一切責任及後果完全由租家承擔，無論租家是否知情。這是基於：租家控制貨物裝入貨櫃的過程，應對其貨源盡到審查義務。", owner:[], charterer:["Sole responsibility for illegal goods in sealed containers"] },
  { no:"R-59", label:"Cl.59", title:"Export + Import Permits", topic:["legal","compliance"], en:"Export and/or import permits for Charterers' cargo to be at Charterers' risk and expense. Charterers to obtain and be responsible for all necessary permits to enter and/or trade in and out of all ports during the currency of this Charter at their own risk and expense. Taxation or levies for these purposes to be for Charterers' account. Charterers to remain responsible to arrange for Standard Carrier Alpha Code (SCAC).", zh:"【進出口許可→租家全責】租家貨物的進出口許可完全由租家自行承擔風險及費用。租家須自行取得並承擔在整個租期內進出所有港口/交易所需的一切許可。相關稅款及徵費由租家支付。租家還須負責取得並維持標準運輸業者字母代碼（SCAC）。", owner:[], charterer:["All import/export permits, taxes and SCAC"] },
  { no:"R-60", label:"Cl.60", title:"Bills of Lading", topic:["bl"], en:"Charterers' bills of lading to be issued. All bills of lading shall be without prejudice to this Charter and Charterers shall indemnify Owners against all consequences or liabilities which may arise from any inconsistency between this Charter and any bills of lading or waybills signed by Charterers, their agents, or by the Captain at their request. Modifies BOXTIME Cl.15.", zh:"【提單由租家出具】提單以租家名義出具。所有提單均不影響本合約，租家須賠償船東因本合約與租家/其代理/船長（應租家要求）簽發的任何提單或運費單之間不一致而產生的一切後果或責任。這是租家控制商業安排的體現，相應地也需承擔由此產生的責任。此條款修改BOXTIME Cl.14(b)。", owner:[], charterer:["Indemnify Owners for any B/L inconsistency with C/P"] },
  { no:"R-61", label:"Cl.61", title:"Stowaways", topic:["cargo","legal","crew"], en:"(AA) Charterers' responsibility: If stowaways gain access by secreting in Charterers' goods/sealed containers, this constitutes breach by Charterers. All time lost, expenses and fines for Charterers' account; vessel remains on hire. Charterers to provide bail if vessel arrested. (BB) Owners' responsibility: If stowaways gain access by other means despite Owners' due diligence, all expenses and fines for Owners' account; vessel off-hire. Owners to provide bail if vessel arrested.", zh:"【(AA)偷渡者藏匿於租家貨物→租家違約】若偷渡者通過藏匿於租家的貨物或密封貨櫃上船，此行為構成租家違約。所有時間損失、費用及罰款由租家承擔；船舶仍計租（remains on hire）；如船舶被逮捕，租家須自費提供擔保使其盡快獲釋。【(BB)其他途徑上船→船東責任】若偷渡者通過其他途徑上船（儘管船東已盡職責），所有費用及罰款由船東承擔；船舶off-hire；如船舶被逮捕，船東須自費提供擔保。", owner:["Time, fines and costs if stowaways board by non-cargo means (off-hire)"], charterer:["Time, fines and costs if stowaways hide in cargo/containers (on hire)"] },
  { no:"R-62", label:"Cl.62", title:"Sale Clause", topic:["ownership"], en:"During the charter period, Owners have the option to sell the vessel subject to minimum 30 days' prior written notice to Charterers. Change of ownership subject to Charterers' prior approval to be declared within 10 running days of notice, not to be unreasonably withheld. A tripartite agreement between Owners/Buyers/Charterers is required. No vessel name/flag/registry/class/ownership change without 30 days notice and Charterers' prior consent. Any time lost due to such changes to count as off-hire; bunkers consumed for Owners' account.", zh:"【租期內出售船舶的程序】船東有意出售時：需提前至少30天書面通知租家。租家須在收到通知後10個運行天內宣告是否批准（不得無理拒絕）。需簽訂三方協議（船東/買家/租家）確立租約轉讓的各方權利義務。【船名/船旗/船籍/船級/所有權變更】任何此類變更均需提前30天通知及租家事先同意（不得無理拒絕）。因此類變更造成的任何時間損失計為off-hire，燃油消耗由船東負責。", owner:["Off-hire time and bunkers for name/flag changes"], charterer:[] },
  { no:"R-63", label:"Cl.63", title:"Epidemic Clause", topic:["trading","safety"], en:"The vessel shall not be ordered to enter any port or area where epidemics or infectious diseases are prevalent without Owners' prior consent. If Owners' consent is given, any costs and consequences arising from Charterers' orders to call such place shall be for Charterers' account. Charterers are not allowed to place the vessel off-hire for any delay resulting from their orders to enter such areas.", zh:"【疫情區域限制】船舶不得被指令進入疫情或傳染病流行的港口或區域，除非先獲得船東書面同意。若船東同意：租家承擔一切由此產生的費用和後果；租家不得以此主張off-hire，即便因此造成延誤。這保護船員健康及船東保險效力。", owner:[], charterer:["All costs and consequences of calling epidemic areas; no off-hire claim"] },
  { no:"R-64", label:"Cl.64", title:"Dangerous Goods", topic:["cargo","safety"], en:"Charterers have the liberty of shipping SOLAS/IMDG Classes 1–9 in freight containers or portable tanks, always properly classified, marked, labelled, stowed and discharged per IMDG Code and local regulations. Any special safety equipment, modifications or extra insurance required by IMDG/IMO/port regulations to be provided and paid by Charterers. Generally excluded: ammunition and arms (other than sporting/hunting), military equipment and weapons, explosives, calcium hypochloride (IMDG 5.1), radioactive or nuclear products, toxic substances (Class 6.1), wet hides, livestock, and cargo subject to UN/flag state boycott.", zh:"【危險品裝運範圍】租家有權裝運SOLAS/IMDG第1-9類危險品（以貨運貨櫃或便攜式罐體形式），但必須嚴格按照IMDG規範、當地強制要求及船旗國法規進行正確分類、標記、標籤、裝載、積載及卸貨。任何IMDG/IMO/港口法規要求的特殊安全設備、改裝或額外保險由租家提供並支付。【明確禁運貨物】軍火武器（運動/狩獵用途除外）、軍事設備、爆炸物、次氯酸鈣（IMDG 5.1類）、放射性或核產品、有毒物質（6.1類）、濕皮革、活體牲畜、以及受聯合國或船旗國抵制的貨物。", owner:[], charterer:["Special equipment, modifications and extra insurance for DG"] },
  { no:"R-65", label:"Cl.65", title:"[DELETED]", topic:[], deleted:true, en:"This clause has been deleted from the Charter Party.", zh:"【已刪除】本條款在本合約中已被刪除，不適用。", owner:[], charterer:[] },
  { no:"R-66", label:"Cl.66", title:"Joint On/Off Hire Survey", topic:["delivery","redelivery","survey"], en:"A joint survey to be held prior to delivery (in Owners' time) and at redelivery (in Charterers' time) to ascertain the vessel's condition and quantities of fuel oil, diesel oil, galley fuel and fresh water remaining on board. Expenses to be shared equally.", zh:"【聯合驗船時機及費用】交船驗船：在交船地點進行，耗用船東時間（除非交船前船舶已開始裝貨）。還船驗船：在還船地點進行，耗用租家時間。驗船師由雙方共同接受的人選擔任。【費用分攤】驗船費用由船東/租家平均分攤。【驗船內容】船況及船上所有燃油（含柴油、廚房燃料及淡水）數量。船東確保船長、大管輪、船員配合驗船師工作。", owner:["50% survey cost"], charterer:["50% survey cost"] },
  { no:"R-67", label:"Cl.67", title:"Reefer Container", topic:["cargo","reefer","maintenance"], en:"Vessel has 319 reefer plugs. Charterers to provide written cooling and ventilation instructions to Master before loading. Owners to monitor reefer performance minimum twice daily (weather permitting). For repairs: USD 10 per man/hour against time sheets signed by Master/Chief Officer; spare parts for Charterers' account. No funds to be paid directly to the Master. Owners not responsible for reefer malfunction except in case of power failure.", zh:"【冷凍插座數量】船舶配備319個冷凍貨櫃插座。【裝船前準備】租家須在裝貨前以書面向船長提供所有冷凍及通風指示。【監控義務→船東】天氣及海況允許時，船東須每日至少監測2次冷凍貨櫃的運行情況，並記錄性能。【維修費用→租家】每次維修按USD 10/人/小時收費，憑船長/大副簽名確認的工時表計算；備件由租家承擔費用；不得直接向船長支付任何款項，所有結算在船東與租家之間進行。【船東責任範圍】船東對冷凍貨櫃故障不負責任，唯一例外是船舶停電（power failure）導致的故障。其他所有原因導致的故障均由租家風險及費用承擔。", owner:["Power failure causing reefer malfunction"], charterer:["USD 10/hr repair labour","Spare parts","All other reefer malfunctions"] },
  { no:"R-68", label:"Cl.68", title:"Lubricating Oil", topic:["cost","maintenance"], en:"Owners to provide and pay for all lubricating oil, for all deck and engine-room stores, and to maintain the vessel's class and keep the vessel in a thoroughly efficient state in hull and machinery during service.", zh:"【潤滑油→船東全包】船東提供並支付所有甲板及輪機部門所需的潤滑油及所有船用物料費用，以維持船舶船級及在整個服務期間保持完全有效的船體和機械狀態。這是船東維持船舶適航狀態義務的一部分。", owner:["All lubricating oil costs"], charterer:[] },
  { no:"R-69", label:"Cl.69", title:"Bunkers Quality", topic:["bunker"], en:"As per Clause 65 (deleted). Refer to Cl.86 (Bunker Quality Control) and Cl.92/98 (Sulphur Content Clauses) for applicable bunker quality provisions.", zh:"【依相關條款辦理】燃油品質依Cl.65辦理（已刪除）。實際適用的燃油品質規定見Rider Cl.86（燃油品質控制）及Cl.92/98（硫含量條款）。", owner:[], charterer:[] },
  { no:"R-70", label:"Cl.70", title:"Vessel's Lashing Equipment", topic:["cargo","maintenance","lashing"], en:"Vessel to be responsible for all container securing gears in good condition of sufficient strength on board (sufficient for a full load of containers up to the vessel's maximum capacity) on delivery for Charterers' use. Vessel to be equipped for Hi Cube containers 9'6\". Vessel to be equipped with sufficient lashing materials/fittings/stack cones/twistlocks (OSHA fitted) up to maximum nominal intakes on delivery; same to be maintained by Owners during this Charter Party.", zh:"【交船時的綁固設備標準】交船時船舶須備有足量且強度足夠的貨櫃固定設備，足以承載船舶最大載量的貨櫃（含9'6\"高箱Hi Cube），且須達OSHA標準。具體要求：足夠的綁固材料/配件/堆疊錐/扭鎖，達到最大名義載量。此設備在整個租期由船東維護保養。綁固力須足以承受最大均勻/名義載量的要求。此設備在整個租期由船東維護保養，twistlocks/stack cones/繫固材料均包含在內。", owner:["Maintain all lashing equipment throughout charter"], charterer:[] },
  { no:"R-71", label:"Cl.71", title:"Bunker Samples", topic:["bunker"], en:"All bunker samples testing arranged by the Owners to be for Owners' account.", zh:"【油樣化驗費用→船東】船東安排的所有燃油樣本化驗費用由船東承擔（除非係應租家要求進行化驗）。保存完好的燃油樣本是解決燃油品質爭議的關鍵證據。", owner:["Bunker sample testing costs"], charterer:[] },
  { no:"R-72", label:"Cl.72", title:"Blacklist", topic:["trading","compliance"], en:"Owners guarantee vessel is not blacklisted with any countries.", zh:"【無黑名單保證】船東保證船舶未被任何國家列入黑名單。這是對船舶商業可用性的保證，確保船舶在指定交易範圍內不會因歷史原因被拒絕進入任何港口。", owner:["Warrant vessel not blacklisted"], charterer:[] },
  { no:"R-73", label:"Cl.73", title:"Confidentiality", topic:["legal"], en:"All negotiations and eventual fixture to be kept strictly private and confidential.", zh:"【嚴格保密義務】所有租船談判過程及最終成交的所有條款內容均須嚴格保密。任何一方不得向第三方（包括其他船東、租家或媒體）透露租金費率、租期、交還船條件等商業條款。", owner:[], charterer:[] },
  { no:"R-74", label:"Cl.74", title:"Ownership Formalities", topic:["ownership","delivery"], en:"Owners to perform vessel's change of ownership formalities (i.e. change of vessel's name, obtaining new certificates, paintings and art work/logo) prior to delivery of vessel to Charterers.", zh:"【交船前完成所有手續】船東須在向租家交船前完成所有所有權轉移手續，包括：更改船名（需當局批准）；取得以新名稱登記的所有新證書；完成船舶塗裝及標誌/標識的更換。確保租家在接收時得到一艘完全符合合約描述的船舶。", owner:["Complete all ownership formalities before delivery"], charterer:[] },
  { no:"R-75", label:"Cl.75", title:"BIMCO CONWARTIME 2004", topic:["war","trading","insurance"], en:"Applies only if vessel is not sailing within Charterers' East Africa trade (AEF Service). 'War Risks' includes: actual/threatened war, civil war, hostilities, piracy, terrorism, mines, blockades and other risks deemed dangerous. Vessel not required to sail into war risk areas without Owners' written consent. Any additional insurance premiums or crew bonuses/extra wages resulting from Charterers' orders to enter war risk areas to be reimbursed at next hire payment. Vessel has liberty to comply with government/war risk underwriters/UN orders. Actions under this clause do not constitute deviation. Supplements BOXTIME Cl.18.", zh:"【適用範圍】本條款僅適用於船舶不在租家東非（AEF服務）航線的情況。【戰爭風險定義】涵蓋：實際或威脅性的戰爭、內戰、敵對行動、海盜行為、恐怖主義、水雷、封鎖及其他被視為危險的風險。【進入戰區程序】未獲船東書面同意，船舶無須進入戰爭風險區域。【費用安排】因租家指令進入戰區產生的：額外保費、船員戰區津貼/額外工資，在下次hire支付時補償給船東。【自由條款】船舶有自由遵從政府、戰爭風險保險人或聯合國的命令；依本條款採取的任何行動均不構成偏航。此條款補充並修改BOXTIME Cl.19。", owner:[], charterer:["Additional war risk premiums","Crew bonuses/wages for war risk areas"] },
  { no:"R-76", label:"Cl.76", title:"BIMCO ISPS/MTSA Clause 2005", topic:["security","compliance"], en:"Owners to comply with ISPS Code requirements relating to vessel and 'the Company'. If trading to/from US waters, to also comply with MTSA. Owners to provide ISSC (or Interim ISSC) and CSO contact details on request. Charterers to provide contact details and info necessary for ISPS/MTSA compliance; if sub-letting, to ensure sub-charterers' info is provided. All costs from port security regulations (guards, escorts, fees) for Charterers' account unless due to Owners'/Master's/crew's negligence.", zh:"【ISPS合規義務→船東】船東須遵守ISPS（International Ship and Port Facility Security Code）關於船舶及「公司」的所有要求；如在美國水域交易，還須遵守MTSA（Maritime Transportation Security Act）。船東須根據要求提供ISSC（或臨時ISSC）及CSO（公司保安員）聯絡資料。【租家配合義務】租家須提供ISPS/MTSA合規所需的聯絡資訊；若轉租，須確保次租家的信息也被提供。【費用負擔】港口保安法規要求的費用（守衛、護送、費用等）由租家承擔，除非係因船東/船長/船員的疏忽造成。", owner:["Vessel ISPS compliance and ISSC certificate"], charterer:["Port security costs (guards, escorts, fees)"] },
  { no:"R-77", label:"Cl.77", title:"New Jason Clause", topic:["ga","bl"], en:"In the event of accident, danger, damage or disaster, for which the Carrier is not responsible by statute, contract or otherwise, the goods, shippers, consignees or owners of the goods shall contribute with the Carrier in General Average and shall pay salvage and special charges incurred in respect of the goods. Charterers shall procure that all Bills of Lading issued under this Charter Party shall contain the same clause. Supplements BOXTIME Cl.19.", zh:"【New Jason Clause核心原則】即使承運人依法規、合約或其他原因對意外、危險、損害或災難不負責任，貨物所有人、托運人、收貨人也必須就船上貨物的共同海損、救助及特別費用與承運人共同分攤。【提單要求→租家義務】租家須確保本合約下簽發的所有提單均包含相同的Jason Clause條款。此條款補充BOXTIME Cl.14(c)的共同海損規定。", owner:[], charterer:["Ensure all B/Ls incorporate New Jason Clause"] },
  { no:"R-78", label:"Cl.78", title:"General Clause Paramount", topic:["legal","bl"], en:"The Hague-Visby Rules (Brussels Convention 1924 as amended by the Protocol of 23 February 1968 and the SDR Protocol 1979) as enacted in the country of shipment shall apply. Where not enacted, the legislation of the country of destination applies. The Carrier shall in no case be responsible for loss of or damage to cargo arising prior to loading, after discharging, while in the charge of another carrier, or with respect to deck cargo and live animals.", zh:"【海牙-維斯比規則適用】本合約受裝貨地國家所實施的海牙-維斯比規則（1924年布魯塞爾公約及1968年和1979年議定書修正版）約束。若裝貨地未實施，則適用目的地國家的法規。【承運人免責範圍】承運人對以下情況的貨損不負責任：(1)裝貨前的損失；(2)卸貨後的損失；(3)由其他承運人負責期間的損失；(4)甲板貨（按已知甲板裝載方式裝運的貨物）；(5)活體動物。", owner:[], charterer:[] },
  { no:"R-79", label:"Cl.79", title:"New Both-to-Blame Collision Clause", topic:["legal","bl"], en:"If the vessel comes into collision with another ship as a result of the negligence of the other ship and any act, neglect or default of the Master or crew in the navigation or management of the ship, the owners of the goods carried hereunder will indemnify the Carrier against all loss or liability to the other ship insofar as such loss or liability represents loss of, damage to, or any claim of the owners of the said goods. Charterers shall procure that all Bills of Lading shall contain the same clause.", zh:"【雙方碰撞條款的背景】主要針對美國法律下的特殊問題：美國法律允許碰撞中受損貨物的所有人向碰撞另一方船舶索賠，而不管哪方過失，這可能導致承運人間接承擔不應承擔的責任。【條款機制】若本船與另一船舶碰撞，且雙方均有過失，本船所載貨物所有人須補償承運人因貨物損失索賠而向另一船舶支付的金額。【提單要求→租家義務】租家須確保所有提單包含相同的Both-to-Blame Collision Clause。", owner:[], charterer:["Ensure all B/Ls incorporate Both-to-Blame clause"] },
  { no:"R-80", label:"Cl.80", title:"Hamburg Rules", topic:["legal","bl"], en:"Neither the Charterers nor their agents shall permit the issue of any Bill of Lading incorporating, where not compulsorily applicable, the Hamburg Rules or any other legislation imposing liabilities in excess of the Hague-Visby Rules. Charterers shall indemnify Owners against any liability resulting from breach of this provision.", zh:"【禁止在提單中引用漢堡規則】除非漢堡規則在相關地區強制適用，否則租家及其代理不得在任何提單或運費單中引用漢堡規則或任何使責任超過海牙-維斯比規則的法規。【違反後果】若租家違反此規定，須賠償船東因適用超過海牙-維斯比規則標準的更高責任而遭受的一切損失。背景：漢堡規則對承運人的責任要求遠高於海牙-維斯比規則，對船東不利。", owner:[], charterer:["Prohibited from incorporating Hamburg Rules in B/Ls unless mandatory"] },
  { no:"R-81", label:"Cl.81", title:"BIMCO Double Banking Clause", topic:["cargo","operations"], en:"Charterers have the right to order the vessel to go alongside another vessel for transhipment, loading/discharging, or bunkering, where customary and safe. Charterers to provide assistance and equipment and give advance notice. Master has the right to refuse if in his reasonable opinion it is not safe. Charterers reimburse additional insurance premiums and hull deductible. Charterers indemnify Owners for all costs, damage and liabilities; vessel remains on hire during repairs.", zh:"【BIMCO雙船並靠條款的前提】在符合習慣做法且安全的條件下，租家有權指令船舶靠近另一船舶進行轉運、裝卸或加油。【操作要求】租家須提供必要協助和設備，並盡早通知。船長有權在其合理判斷認為不安全時拒絕執行。【費用和責任→租家】租家補償額外保費及船殼險扣款（deductible）；租家對所有費用、損害及責任承擔賠償責任；修理期間船舶仍計租。", owner:[], charterer:["All costs, damage, and additional insurance for double banking"] },
  { no:"R-82", label:"Cl.82", title:"P&I Financial Security – Pollution", topic:["environment","insurance","compliance"], en:"Owners warrant to maintain throughout the charter: (A) Bunker Convention certificate (if vessel >1,000 GT calling Convention states); (B) CLC 1992 certificate (if carrying persistent oil in bulk >2,000 tonnes); (C) OPA 1990 / CERCLA certificate (if entering US navigable waters, vessel >300 GT). Beyond these statutory requirements, any additional financial security requirements are for Charterers' account. Charterers to ensure B/Ls incorporate this clause.", zh:"【船東須維持的三類法定污染責任憑證】(A)燃油污染保險憑證：適用於超過1,000總噸、掛靠公約締約國港口的船舶（依燃油污染公約）；(B)CLC 1992憑證：適用於散裝持久性石油超過2,000噸的船舶（依民事責任公約）；(C)OPA 1990/CERCLA憑證：適用於進入美國通航水域且超過300總噸的船舶（依美國相關法規）。【超出法定要求的部分→租家承擔後果】任何超出上述法定要求的額外財務保障要求（如特定港口或國家的額外要求）的後果由租家承擔。", owner:["Maintain 3 statutory pollution certificates"], charterer:["Consequences of additional non-statutory financial security requirements"] },
  { no:"R-83", label:"Cl.83", title:"US Anti Drug Abuse Act 1986", topic:["security","compliance","legal"], en:"Charterers warrant to exercise the highest degree of care and diligence in preventing unmanifested narcotic drugs and marijuana from being loaded or concealed on board. Non-compliance constitutes breach of warranty; all fines, time lost, and costs for Charterers' account; vessel remains on hire. If vessel arrested, Charterers to provide bail at their expense. Owners responsible if drugs found in possession of vessel's personnel. Both parties to become signatories to the Sea Carrier Initiative Agreement.", zh:"【租家最高程度的防毒義務】租家保證採取最嚴格的謹慎和勤勉措施，防止未申報的麻醉藥品和大麻藥物被裝上船或藏入船中。【違反後果→租家全責，船仍計租】違反此保證構成合約違約；所有罰款、時間損失及費用由租家承擔；船舶仍計租（remains on hire）；如船舶被逮捕，租家須自費盡快使其獲釋，包括提供擔保金。【船員個人持有毒品→船東責任】若毒品發現於船員個人持有物，則由船東承擔責任。【海上運輸業者協議】雙方均須成為Sea Carrier Initiative Agreement（海上運輸業者主動倡議協議）的簽署方。", owner:["Responsible if drugs are vessel personnel's own possession"], charterer:["Highest diligence to prevent unmanifested drugs; all fines if breach"] },
  { no:"R-84", label:"Cl.84", title:"C-TPAT Clause", topic:["security","compliance"], en:"Charterers have voluntarily signed the C-TPAT Agreement with US Customs Service. Owners/Master/crew will use reasonable efforts to assist Charterers in complying. Owners/Master/crew shall not be liable for any delays, losses or damages arising from failure to meet C-TPAT requirements. Charterers to indemnify and hold Owners, Master and crew harmless for all claims arising from the C-TPAT Agreement.", zh:"【C-TPAT背景】C-TPAT（Customs-Trade Partnership Against Terrorism，海關貿易反恐夥伴協定）是美國海關與租家自願簽署的反恐合規框架。租家已自願簽署。【船東有限協助義務】船東/船長/船員將盡合理努力協助租家遵守C-TPAT要求，但對因未能達到C-TPAT要求而產生的任何延誤、損失或損害不承擔責任。【索賠及費用→租家全責】租家須賠償並保持船東、船長及船員免受因C-TPAT協議產生的一切索賠的損害。", owner:[], charterer:["All claims and costs arising from C-TPAT Agreement"] },
  { no:"R-85", label:"Cl.85", title:"[DELETED] US Security Clause", topic:[], deleted:true, en:"This clause (US Security Clause for Time Chartering) has been deleted from the Charter Party.", zh:"【已刪除】本條款（US Security Clause for Time Chartering，時間租船的美國保安條款）在本合約中已被刪除，不適用。", owner:[], charterer:[] },
  { no:"R-86", label:"Cl.86", title:"Bunker Quality Control Clause", topic:["bunker"], en:"Charterers to supply bunkers of a quality suitable for burning in the vessel's engines and auxiliaries, conforming to mutually agreed specifications. On delivery, Owners to provide bunker delivery notes and samples. Samples retained for 90 days (or longer if dispute). Any dispute as to bunker fuel conformity to be settled by analysis of samples by a mutually agreed analyst whose findings are conclusive. Owners reserve the right to claim for damage to main engines or auxiliaries caused by unsuitable fuels.", zh:"【燃油規格要求】租家供應的燃油必須：適合在船舶主機及輔機中燃燒；符合雙方協議的規格。【油樣存證程序】交油時取樣並由供應商、大管輪和租家代理各簽名保存一份樣本，至少保留90天（如有爭議則繼續保留）。【爭議解決】任何燃油品質或規格爭議，由雙方同意的合格燃油分析師化驗，其結論具有最終決定性。【船東追償權】船東保留就不合規燃油造成的主機或輔機損壞向租家追償的權利。", owner:["Provide bunker delivery notes and samples on delivery"], charterer:["Supply bunkers meeting agreed specifications"] },
  { no:"R-87", label:"Cl.87", title:"Terrorism Risk Clause", topic:["war","insurance"], en:"Charterers to provide at their own cost Charterers' Liability Insurance covering loss or damage caused by War Risks (including terrorism). Owners to provide at their own cost Owners' Liability Insurance covering the same, subject to termination clause (notice of cancellation) under current and future War Risk Policy and P&I Pool rules.", zh:"【雙方各自購買恐怖主義風險保險】租家：自費購買涵蓋因戰爭風險（含恐怖主義）造成的損失或損害的租家責任保險。船東：自費購買同類保險（船東責任部分），受現行及未來戰爭風險保單及P＆I船東互保協會條款的取消通知約束。背景：恐怖主義風險對航運業是重大威脅，雙方各自對其責任部分購買保險，確保充分保障。", owner:["Own War Risk/terrorism insurance (Owners' liability)"], charterer:["Own War Risk/terrorism insurance (Charterers' liability)"] },
  { no:"R-88", label:"Cl.88", title:"US Customs 24 Hours Rule", topic:["compliance","legal","security"], en:"If loading cargo destined for or transiting US ports, Charterers must submit a cargo declaration to US Customs not later than 24 hours in advance of loading. Charterers assume full liability for non-compliance including all losses, damages, expenses, fines, penalties and legal costs. If vessel detained, Charterers to provide bail at their expense; vessel remains on hire.", zh:"【美國24小時申報規則的適用範圍】凡裝載目的地為美國或過境美國港口的貨物，租家須在裝貨前不少於24小時向美國海關提交貨物申報（AMS申報）。【違反後果→租家全責，船仍計租】租家承擔全部違規責任，包括所有損失、損害、費用、罰款、處罰及法律費用；船舶仍計租；若船舶被拘留，租家須自費盡快使其獲釋，包括提供擔保金。", owner:[], charterer:["24-hour pre-loading declaration to US Customs; all fines for non-compliance"] },
  { no:"R-89", label:"Cl.89", title:"US Trade Unique Bill of Lading Identification", topic:["bl","compliance"], en:"Charterers warrant that each transport document accompanying a shipment to a US port shall be endorsed with a Unique Bill of Lading Identifier as required by US Customs Regulations (19 CFR Part 4 Section 4.7A) not later than the first port of call. Non-compliance constitutes breach of warranty; all consequences, time lost and fines for Charterers' account.", zh:"【美國貿易提單唯一識別碼要求】租家保證每份運往美國港口的運送文件均在第一靠港前，依美國海關法規（19 CFR第4部分4.7A節）的要求加蓋唯一提單識別碼。【違反後果→租家全責】違反此保證構成合約違約；一切後果、時間損失及罰款由租家承擔，並賠償船東的損失。", owner:[], charterer:["Endorse all US-destined B/Ls with unique identifier before first port"] },
  { no:"R-90", label:"Cl.90", title:"[DELETED]", topic:[], deleted:true, en:"This clause has been deleted from the Charter Party.", zh:"【已刪除】本條款在本合約中已被刪除，不適用。", owner:[], charterer:[] },
  { no:"R-91", label:"Cl.91", title:"Pollution", topic:["environment","offhire"], en:"Owners warrant that during the currency of this Charter Party, the vessel will comply with all international, governmental, state and provincial rules and regulations pertaining to water pollution applicable in countries where the vessel trades. If the vessel fails to comply, causing costs, expenses, fines or delay, the vessel shall be considered off-hire for the period of delay; Owners accept full responsibility and shall indemnify Charterers against all claims, liabilities, costs and expenses.", zh:"【水污染合規義務→船東】船東保證在整個租期內，船舶在所有交易國家遵守所有有關水污染的國際、政府、州及省級法規。【違規後果→off-hire及全額賠償】若因違規造成費用、罰款或延誤，延誤期間視為off-hire；船東承擔全部責任並賠償租家的一切索賠、責任、費用及損失。", owner:["Full compliance with water pollution regulations; off-hire if non-compliant"], charterer:[] },
  { no:"R-92", label:"Cl.92", title:"Bunker Fuel Sulphur Content Clause 2005", topic:["bunker","environment","compliance"], en:"Charterers to supply fuels permitting the vessel to comply with maximum sulphur content requirements in any Emission Control Area (ECA). Charterers warrant that bunker suppliers comply with MARPOL Annex VI Regulations 14 and 18. Charterers to indemnify Owners for non-compliance; vessel remains on hire. If Charterers have supplied compliant fuel, Owners warrant the vessel shall comply and be capable of consuming such fuels. 'ECA' includes MARPOL zones and regional/national zones (EU, US EPA etc.).", zh:"【租家供應符合ECA標準的燃油義務】租家須供應允許船舶在任何排放控制區（ECA）內符合最高含硫量要求的燃油，並保證燃油供應商遵守MARPOL附則VI第14和18條（含取樣及燃油交付憑證）。【違規後果→船仍計租，租家賠償】若租家不合規，須賠償船東；船舶仍計租。【船東對應義務】若租家已按本條款供應合規燃油，船東保證船舶合規且能使用此類燃油。「ECA」包括MARPOL規定的區域及各地區/國家的排放控制區（如歐盟、美國EPA等）。補充BOXTIME Cl.12(c)。", owner:["Warrant vessel can consume and comply with sulphur reqs"], charterer:["Supply ECA-compliant fuel; warrant supplier compliance"] },
  { no:"R-93", label:"Cl.93", title:"US AES – Automated Export System", topic:["compliance","legal"], en:"If vessel loads cargo in any US port, Charterers to comply with US Census Bureau Regulations (15 CFR 30), assume role of carrier, and at their own expense: (i) have SCAC; (ii) have ICB; (iii) confirm to Owners; (iv) submit Export Ocean Manifest via AES and provide copy to Owners. Non-compliance fines for Charterers' account; vessel remains on hire.", zh:"【美國AES出口申報系統的義務】凡在任何美國港口裝貨，租家須遵守美國人口普查局法規（15 CFR 30），以承運人身份：(i)取得SCAC（標準運輸業者字母代碼）；(ii)取得ICB（簽發方代碼）；(iii)向船東確認上述代碼；(iv)通過AES向美國人口普查局提交出口海運艙單並提供副本給船東。【違規責任→租家，船仍計租】所有違規責任、罰款、處罰及法律費用由租家承擔；船舶仍計租。【特殊情況】若租家的ICB被用來支付本應由船東承擔的費用，船東須立即向租家報銷。", owner:["Reimburse Charterers if Owners' charges paid via Charterers' ICB"], charterer:["Obtain SCAC and ICB; submit AES export manifest"] },
  { no:"R-94", label:"Cl.94", title:"No Direct Payment to Master / Crew", topic:["crew","hire"], en:"In any circumstances, Charterers not to pay any funds directly to the Master and the crew. All settlements shall be proceeded between Owners and Charterers only.", zh:"【禁止直接支付的原則】任何情況下，租家不得直接向船長或任何船員支付任何款項。所有款項結算僅在船東與租家之間進行。背景：直接向船員支付款項可能導致利益衝突、不透明的賬務，甚至引發腐敗問題。所有服務費用應通過正式的船東-租家賬務渠道結算。", owner:[], charterer:["Prohibited from making direct payment to Master or crew"] },
  { no:"R-95", label:"Cl.95", title:"Crew Assistance", topic:["crew","cargo","lashing"], en:"Charterers acknowledge that crew availability for work as Charterers' servants is increasingly limited due to STCW, ISPS, and ITF/union requirements. In exceptional cases only, and provided allowed by local port and/or union regulations, crew will assist in lashing/unlashing, securing/unsecuring, plugging/unplugging of containers. Charterers to pay relevant crew bonus per their standard tariff.", zh:"【船員協助的現實限制】租家了解並承認，由於STCW（海員培訓、發證和值班標準公約）、ISPS及ITF/工會法規的限制，船員作為租家受僱人提供服務的可能性日益受限。【協助條件】僅在例外情況下，且在當地港口和/或工會法規允許的前提下，船員才能協助進行：貨物綁紮/解紮、貨物固定/解固、貨櫃電源插拔。【費用→租家支付船員獎金】租家須按船東的標準費率向相關船員支付獎金。", owner:[], charterer:["Pay crew bonus per standard tariff for assistance"] },
  { no:"R-96", label:"Cl.96", title:"BIMCO SSS Clause – Slow/Ultra-Slow Steaming", topic:["speed","bunker","environment"], en:"(A)(i) Slow steaming: Charterers may in writing instruct Master to reduce speed/RPM, provided engine operates above auxiliary blower cut-out point and within manufacturer's recommendations. (A)(ii) Ultra-slow steaming: Even if engine operates below auxiliary blower cut-out point, Master to comply if within manufacturer's recommendations. Subclauses (i) and (ii) are alternatives; (i) applies if neither is deleted. (B/C) Owners to exercise due diligence to minimise fuel consumption via voyage planning, trim adjustment, weather routing, and voyage optimisation. (E) Compliance does not constitute breach of due despatch. (F) Charterers to ensure B/Ls reflect this. Note: (E) and (F) not applicable in liner trade.", zh:"【慢速航行指令】租家可以書面形式指令船長降低船速/轉速，條件是：(i)慢速：引擎在輔助鼓風機切入點以上運作，且在製造商建議範圍內；(ii)超慢速：即使引擎在輔助鼓風機切入點以下也須遵從，但仍需在製造商建議範圍內。(i)和(ii)為替代選項，若均未刪除則適用(i)。【船東節能義務】船東須通過以下方式盡力節省燃油：航行計劃優化、縱傾調整、氣象航行及航次優化。雙方應共享節能改進結果。【不構成違約】遵守本條款的指示不構成違反「盡速航行」義務或任何類似義務（E款）。租家須確保提單反映慢速航行合規不構成運輸合同違約（F款）。注意：E款及F款不適用於班輪服務。", owner:["Due diligence to minimise fuel consumption"], charterer:["Right to issue written slow/ultra-slow steaming instructions"] },
  { no:"R-97", label:"Cl.97", title:"BIMCO 2020 Fuel Transition Clause", topic:["bunker","environment","compliance"], en:"Effective Date: 1 January 2020. Carriage Ban Date: 1 March 2020. Non-compliant fuel = sulphur >0.50%. Charterers to supply sufficient compliant fuel before Effective Date. By Carriage Ban Date, Charterers to discharge all non-compliant fuel at their cost. Owners to clean and prepare empty tanks at their cost. Compliant fuel not loaded until tanks ready. Each supply to be bunkered into empty tanks within vessel's natural segregation.", zh:"【IMO 2020過渡的時間表】生效日期：2020年1月1日。禁運日期：2020年3月1日。「不合規燃油」= 硫含量超過0.50%的燃油。生效日期前：租家須供應足夠的合規燃油（≤0.50%）使船舶到達最近的加油港。禁運日期前：(1)不得再有不合規燃油留存（租家須以其風險和費用卸走/處置所有不合規燃油）；(2)船東須以其風險和費用清潔並準備好空艙接收合規燃油；(3)合規燃油須在油艙清潔完成後才能加注；(4)每批合規燃油須加入船舶自然隔離的空艙中。", owner:["Clean and prepare tanks to receive compliant fuel"], charterer:["Discharge and dispose of non-compliant fuel before Carriage Ban Date"] },
  { no:"R-98", label:"Cl.98", title:"BIMCO 2020 Marine Fuel Sulphur Content Clause", topic:["bunker","environment","compliance"], en:"Charterers to supply fuels complying with all sulphur content requirements (MARPOL Annex VI and/or other applicable authority) at all times. Charterers warrant bunker suppliers comply. Charterers indemnify Owners for non-compliance; vessel remains on hire. Owners warrant vessel complies with sulphur requirements. If Charterers supplied compliant fuel, Charterers not liable for Owners' failure to comply.", zh:"【含硫量要求適用範圍】「含硫量要求」指MARPOL附則VI（及修訂版）及/或其他適用當局的要求。【租家義務】供應符合所有含硫量要求的燃油；保證燃油供應商、燃油駁船運營商及油量測量員遵守含硫量要求；若不合規則賠償船東（船仍計租）。【船東義務】保證船舶符合含硫量要求。【責任分配】若租家已按本條款供應合規燃油，租家不對船東自身違規負責。", owner:["Warrant vessel complies with sulphur requirements"], charterer:["Supply compliant fuel; warrant supplier compliance; indemnify Owners if non-compliant"] },
  { no:"R-99", label:"Cl.99", title:"Hull Cleaning Before Delivery", topic:["delivery","maintenance","performance"], en:"If vessel is idle for 20 days or more before delivery, Owners to arrange at their own cost underwater hull cleaning including propeller and rudder polishing 3 days before delivery and provide hull clean report and photos to Charterers.", zh:"【交船前船底清洗要求】若船舶在交船前閒置20天或以上，船東須在交船前3天內自費安排水下船底清洗（包括螺旋槳和舵的拋光），並向租家提供清洗報告和照片。背景：閒置期間船底會迅速積累生物附著（如藤壺），嚴重影響船速和燃油消耗，這一要求確保租家接收到一艘船底乾淨、性能正常的船舶。", owner:["Hull/propeller/rudder cleaning if idle ≥20 days before delivery"], charterer:[] },
];

// ─── QUIZ BANKS ───────────────────────────────────────────────────────────────
const BT_QUIZ = [
  // Cl.1 – Period of Charter Party and Delivery (2 questions)
  { q:"Cl.1: The vessel cannot be delivered by the cancelling date and Owners notify Charterers. How long do Charterers have to decide whether to cancel or accept delivery?", opts:["48 hours","24 hours","72 hours","7 working days"], ans:1, exp:"Cl.1(b): if Owners notify that the vessel cannot be delivered by the cancelling date, Charterers must declare within 24 hours of receipt whether they cancel or will take delivery. This is separate from the 48-hour window that applies when Owners give advance notice that the vessel will not be ready in time." },
  { q:"Cl.1: Owners give advance notice before the cancelling date that the vessel will not be ready in time. How long do Charterers have to decide?", opts:["24 hours","48 hours","72 hours","2 working days"], ans:1, exp:"Cl.1(b): if prior to delivery Owners notify Charterers that the vessel will not be ready by the cancelling date, Charterers shall declare within 48 hours of receipt whether they cancel or will take delivery — but without prejudice to their right to claim proved damages." },

  // Cl.7 – Hire (3 questions)
  { q:"Cl.7: Hire has not been paid on time. After Owners issue a default notice, how many running hours do Charterers have to pay before Owners may withdraw?", opts:["48 hours","72 hours","96 running hours","7 days"], ans:2, exp:"Cl.7(c): in default of punctual payment, Owners may require Charterers to make payment within 96 running hours of receipt of notification. Only after that period expires without payment may Owners withdraw the vessel. Interest accrues at 0.1% per day on the outstanding amount." },
  { q:"Cl.7: During the grace period after a default notice, hire remains unpaid and Owners suspend performance. Who bears the cost of consequences from the suspension?", opts:["Owners — they chose to suspend","Charterers — they are in default; extra expenses from suspension are for their account","Split equally","Covered by P&I insurance"], ans:1, exp:"Cl.7(c): while hire remains unpaid, Owners have no responsibility for consequences of suspension, and hire continues to accrue. Charterers have indemnified Owners for all such consequences under the Charter Party. Extra expenses from suspension are for Charterers' account." },
  { q:"Cl.7: The vessel is on her final voyage towards redelivery when the next hire payment falls due. How is the payment amount calculated?", opts:["Full hire instalment as normal","Estimated time to complete voyage to redelivery, less estimated redelivery bunker value and Owners' disbursements","No payment required — final voyage is at Owners' risk","Half the normal instalment"], ans:1, exp:"Cl.7(d) Redelivery Adjustment: if the vessel is on her redelivery voyage when hire falls due, payment shall be made for the estimated time to complete the voyage, less disbursements made by Charterers for Owners' account including estimated redelivery bunker value. Differences are reconciled within 3 months of redelivery." },

  // Cl.8 – Off Hire (3 questions)
  { q:"Cl.8: The vessel's main engine breaks down, partially reducing cargo operations but not stopping them completely. Is the vessel fully or partially off-hire?", opts:["Fully off-hire — any breakdown triggers full off-hire","Partially off-hire for time actually lost, to the extent the incident affects Charterers' use","No off-hire — partial breakdown is not covered","Off-hire only if Charterers formally declare it"], ans:1, exp:"Cl.8(a): if the incident partially affects the use of the vessel, it shall be off-hire 'for time actually lost' to the extent such incidents affect Charterers' use. Full off-hire only applies if the incident affects the full use of the vessel." },
  { q:"Cl.8: The vessel deviates from Charterers' instructions to avoid bad weather and puts into an anchorage. Is the vessel off-hire during this period?", opts:["Yes — any unplanned stop triggers off-hire","No — the vessel remains on hire and all costs are for Charterers' account","Off-hire only if the stop exceeds 12 hours","Yes — deviation to avoid weather is always off-hire"], ans:1, exp:"Cl.8(b): if the vessel alters course to avoid bad weather or is driven into port or anchorage by stress of weather, the vessel shall remain on hire and all costs thereby incurred shall be for Charterers' account. Off-hire only applies to deviations other than to save life or property." },
  { q:"Cl.8: The vessel is trapped in a port by a hostile naval blockade. After how many consecutive days does the Charter Party automatically terminate?", opts:["90 days","180 days","365 days","It never terminates automatically"], ans:2, exp:"Cl.8(c) Blocking and Trapping: if the vessel is blocked or trapped in circumstances where Cl.19(b) War applies, the vessel is off-hire during the blocked/trapped period. If the vessel is blocked or trapped for a period of 365 days, the Charter Party shall be terminated." },

  // Cl.9 – Loss of Vessel (1 question)
  { q:"Cl.9: The vessel is reported missing — no word for several weeks. From what point does hire cease to be payable?", opts:["From the date of the last confirmed port call","From noon on the date when the vessel was last heard of","From the date Owners formally declare a constructive total loss","From the date insurers pay out the H&M claim"], ans:1, exp:"Cl.9: if the vessel is missing, hire ceases from noon on the date when she was last heard of. Any hire paid in advance and not earned shall be returned to Charterers. Payment of hire due is suspended until the vessel is reported safe." },

  // Cl.10 – Lashings and Stevedoring (2 questions)
  { q:"Cl.10: The Classification Society-approved lashing pattern design fails during the voyage, damaging cargo. Who is responsible?", opts:["Charterers — they directed the stowage planning","Owners — they are responsible for failure of lashing pattern design or execution, subject to Cl.17","Stevedores — they physically executed the lashing","Split equally under Interclub Agreement"], ans:1, exp:"Cl.10(e) Liability: Owners are responsible for the consequences of failure of any lashings or lashing pattern design or execution, or failure to properly service lashings during the voyage — subject to the provisions of Cl.17. The only exception is failure of any lashing supplied by Charterers themselves." },
  { q:"Cl.10: Charterers use locally available shore cranes because the vessel's cranes are broken down. Must Owners pay for the shore cranes?", opts:["No — shore cranes are Charterers' operational choice; vessel remains on hire","Yes — Owners pay the shore crane cost capped at the hire payable for that period; vessel not off-hire pro-rata","Yes — Owners pay unlimited shore crane costs with no cap","No — hire is reduced by 50% and Owners pay nothing more"], ans:1, exp:"Cl.11(b): if Charterers continue working using locally available shore cranes, Owners shall pay the crane cost not exceeding the hire payable for that period. In that case the vessel shall not be off-hire on a pro-rata basis. If shore cranes are not available during breakdown, the vessel is pro-rata off-hire and all direct and proven unavoidable expenses are for Owners' account." },

  // Cl.12 – Bunker Fuel (2 questions)
  { q:"Cl.12: A fuel quality dispute arises. Three samples were taken at delivery. What is the agreed resolution mechanism?", opts:["Reference to Owners' P&I Club surveyor","Analysis by a mutually agreed qualified analyst, whose findings are binding","London arbitration under LMAA rules","Average of both parties' independent analyses"], ans:1, exp:"Cl.12(f): in the event of a dispute as to fuel quality or specification, Owners and Charterers agree to have samples analysed by a mutually agreed qualified analyst. Samples are signed by the supplier, Chief Engineer and Charterers' agent — each retaining one sample for 90 days (per Rider Cl.86)." },
  { q:"Cl.12: Who may bunker the vessel prior to delivery and what is the condition?", opts:["Only Owners — they control the vessel pre-delivery","Charterers may pre-bunker, provided it can be accomplished without hindrance to vessel operations","Either party, with 48 hours' notice to the other","Neither party — bunkering only commences at delivery"], ans:1, exp:"Cl.12(b): provided it can be accomplished without hindrance to vessel operations, Owners shall allow Charterers to bunker for Charterers' account prior to delivery. Equally, Charterers shall allow Owners to bunker for Owners' account prior to redelivery." },

  // Cl.16 – Charterers' Responsibilities (2 questions)
  { q:"Cl.16: A cargo claim is made against Owners. The loss was caused partly by Owners' own fault. Under Cl.16(a), who is responsible to third parties?", opts:["Owners — their fault caused the loss","Charterers — Cl.16(a) makes them responsible even if the liability arises wholly or partly from Owners' fault, subject to their right to claim back from Owners under Cl.17","Split in proportion to fault","Determined by the applicable cargo convention"], ans:1, exp:"Cl.16(a): Charterers shall be responsible for all claims in connection with goods and containers 'even if such liability arises wholly or in part by reason of the act, neglect or default of the Owners.' This broad responsibility is balanced by Charterers' express right to initiate recovery against Owners under Cl.17." },
  { q:"Cl.16: Charterers want to settle a cargo claim for USD 4,000 and recover from Owners, without prior consultation. Is this permitted?", opts:["Yes — Charterers have full authority to settle all claims","No — the C/P (Box 32) sets a maximum settlement authority; Charterers must consult Owners before settling amounts above that figure","Yes — amounts under USD 10,000 are always within Charterers' authority","No — all settlements require Owners' written pre-approval regardless of amount"], ans:1, exp:"Cl.16(h) Claims Authority: Charterers shall make no payment in excess of the amount stated in Box 32 in settlement of a claim for which they intend to seek recovery from Owners, without prior consultation with Owners. Charterers are authorised to grant extensions of time, provided Owners receive immediate notice." },

  // Cl.17 – Owners' Responsibilities (1 question)
  { q:"Cl.17: Charterers' integral reefer power pack (placed on board by Charterers) malfunctions, damaging reefer cargo. Are Owners liable?", opts:["Yes — Owners are responsible for all temperature-sensitive cargo on board","No — Cl.17(b) expressly states Owners are not liable for malfunctioning of integral reefer containers and power packs put on board by Charterers","Split 50/50 — Owners provided power and Charterers provided the unit","Depends on whether Charterers gave written temperature instructions"], ans:1, exp:"Cl.17(b): for integral refrigerated containers or blown-air containers with marine refrigeration clip-on units, Owners are responsible for the provision of electrical power only. The clause expressly states Owners shall not be liable for malfunctioning of integral refrigerated containers and power packs put on board by Charterers." },

  // Cl.19 – War (1 question)
  { q:"Cl.19: Owners consent to the vessel proceeding into a war risk area. Which cost is NOT something Charterers must reimburse Owners for?", opts:["Reinstatement of war risk cover on H&M and P&I for the required area","Additional premia to maintain Hull cover while blocked or trapped (up to CTL or 365 days)","Insurance of hire on the vessel for not exceeding 365 days","The vessel's standard base Hull & Machinery premium already in place"], ans:3, exp:"Cl.19(b): if Owners consent, Charterers reimburse: (i) reinstatement of war risks cover on H&M and P&I, (ii) additional premia to maintain Hull cover while blocked/trapped, and (iii) insurance of hire for up to 365 days. The existing base H&M premium is Owners' own operating cost and is not included in what Charterers reimburse." },

  // Cl.20 – Law and Arbitration (1 question)
  { q:"Cl.20: Box 34 in Part I is left blank. Which arbitration option automatically applies?", opts:["New York arbitration under SMA rules","London arbitration under English law (sub-clause (a))","The parties must agree by separate agreement before any arbitration","ICC arbitration in Paris"], ans:1, exp:"Cl.20: sub-clauses (a) London, (b) New York and (c) Alternative are alternatives; indicate the alternative agreed in Box 34. If Box 34 is not filled in, sub-clause (a) shall apply — meaning English law governs and disputes are referred to London arbitration." },

  // Cl.2 – Owners' Undertaking
  { q:"Cl.2: At the time of delivery, the vessel must conform to the description set out in which parts of the Charter Party?", opts:["Parts I and III","Part I only","Parts I, II and III","Part II only"], ans:0, exp:"Cl.2: The Owners undertake that at delivery, the Vessel shall be of the description set out in Parts I and III hereof." },
  { q:"Cl.2: Owners' undertaking regarding the vessel's condition applies at which point in time?", opts:["Throughout the charter period","At the time of delivery only","At delivery and redelivery","At the time of signing"], ans:1, exp:"Cl.2: The Owners undertake that AT DELIVERY, the Vessel shall be of the description set out in Parts I and III hereof." },

  // Cl.3 – Trading Limits
  { q:"Cl.3: The vessel is employed within the IWL trading limits. What obligation does the vessel NOT have under this clause?", opts:["Carry lawful goods","Call only at safe ports","Force ice or follow icebreakers","Trade within Box 22 limits"], ans:2, exp:"Cl.3: The Vessel shall NOT be obliged to force ice nor to follow icebreakers." },
  { q:"Cl.3: Owners warrant that at the time of signing, the vessel has not traded to countries that would make her unacceptable at ports within the Trading Limits. Who provides the list of such countries?", opts:["Owners","Charterers","Flag state authorities","Classification Society"], ans:1, exp:"Cl.3: The Charterers shall provide a list of such countries. See Clause 34." },

  // Cl.4 – Permitted Cargoes
  { q:"Cl.4: Charterers wish to load live animals. Whose consent is required?", opts:["Owners only","Master only","Both Owners and Master","Flag state authority"], ans:2, exp:"Cl.4(c): Live Animals may be carried only with the prior consent of the Owners AND the Master." },
  { q:"Cl.4: Radioactive isotopes may be carried provided they do not invalidate which specific insurance?", opts:["Hull and Machinery insurance","War Risks insurance","P&I cover","Cargo insurance"], ans:2, exp:"Cl.4(d): Radioactive isotopes may be carried only if they are of such a category as not to invalidate the Vessel's P&I cover." },

  // Cl.5 – Owners' Obligations
  { q:"Cl.5: Fumigation certificates are required at the commencement of the Charter Party. Who pays if fumigation is required due to Charterers' cargo?", opts:["Owners","Charterers","Split equally","The port authority"], ans:1, exp:"Cl.5(e): Fumigation required due to Charterers' cargo — costs are for Charterers." },
  { q:"Cl.5: The crew assists with opening and closing hatches. What type of hatches are EXCLUDED from this obligation?", opts:["Weather deck hatches","Engine room hatches","Pontoon type hatches","Hatch covers below deck"], ans:2, exp:"Cl.5(b)(ii): Opening and closing any hatches OTHER THAN pontoon type hatches." },

  // Cl.6 – Charterers' Obligations
  { q:"Cl.6(l): Stevedore damage affecting the vessel's seaworthiness must be repaired in whose time?", opts:["Owners' time","Charterers' time","Equally shared time","Drydock time only"], ans:1, exp:"Cl.6(l): Damage affecting seaworthiness shall be repaired without delay in the CHARTERERS' time and paid for by the Charterers." },
  { q:"Cl.6(m): Charterers are required to give how many days' final notice of redelivery?", opts:["7/5/3 days","5/3/1 days","10/7/3 days","3/2/1 days"], ans:1, exp:"Cl.6(m): Charterers to give 5/3/1 days' notice of redelivery." },
  { q:"Cl.6(o): Charterers' local agents make cash advances to the Master subject to what commission rate?", opts:["1.25%","2.5%","5%","No commission"], ans:1, exp:"Cl.6(o): Funds available to the Master for disbursements subject to 2.5% commission." },

  // Cl.7 – Hire
  { q:"Cl.7(b): If hire is not paid on time, at what daily interest rate must Charterers pay on the outstanding amount?", opts:["0.05% per day","0.1% per day","0.5% per day","LIBOR + 2%"], ans:1, exp:"Cl.7(b): The Charterers shall pay interest at the rate of 0.1 per cent per day on the amount outstanding." },

  // Cl.13 – Charterers' Requirements
  { q:"Cl.13(b): Charterers paint the funnel in their colours during the charter. Who pays for restoring the vessel to its original condition before redelivery?", opts:["Owners","Charterers","Split equally","Whoever initiated the change"], ans:1, exp:"Cl.13(b): Alterations shall be effected during the Charterers' time and at the Charterers' expense, and the vessel shall be returned at Charterers' expense before redelivery." },
  { q:"Cl.13(c): Owners warrant that the vessel can operate in ballast using what types of ballast only?", opts:["Solid ballast and water ballast","Fuel ballast and water ballast","Fuel and water ballast only","Water ballast only"], ans:2, exp:"Cl.13(c): Owners warrant the Vessel is capable of operating in ballast without requiring any solid ballast, using fuel and water ballast only." },
  { q:"Cl.13(k): Charterers wish to sub-let the vessel. Whose prior consent is needed, and can it be unreasonably withheld?", opts:["Owners' consent, and it may be unreasonably withheld","Owners' consent, but shall not be unreasonably withheld","Master's consent only","No consent needed"], ans:1, exp:"Cl.13(k): Sub-letting requires the prior consent of the Owners, which shall NOT be unreasonably withheld." },

  // Cl.14 – Owners' Requirements
  { q:"Cl.14(c): General Average shall not be declared when the estimated amount does not exceed what threshold?", opts:["USD 500,000","USD 1,000,000","USD 2,000,000","USD 250,000"], ans:1, exp:"Cl.14(c): The Owners shall not declare General Average when the amount is estimated not to exceed USD 1,000,000." },
  { q:"Cl.14(d): All salvage proceeds from derelicts are divided between Owners and Charterers. What is first deducted before the split?", opts:["Legal costs","Port disbursements","Master's, Officers' and crew's share","The cost of towage"], ans:2, exp:"Cl.14(d): All salvage and proceeds from derelicts shall be divided equally after deducting the Master's, Officers' and crew's share." },

  // Cl.15 – Sundry Matters
  { q:"Cl.15(c): A stowaway is found on board. Who bears the costs if it is established the stowaway hid inside Charterers' containers prior to loading?", opts:["Owners","Charterers","Split equally","Port authority"], ans:1, exp:"Cl.15(c): If the stowaway gained access by secreting away in Charterers' goods/containers prior to loading, all costs are for the CHARTERERS' account." },
  { q:"Cl.15(d): On/off hire survey expenses are how shared between Owners and Charterers?", opts:["Owners pay all","Charterers pay all","Equally shared","Paid by whoever requests the survey"], ans:2, exp:"Cl.15(d): Surveying expense to be equally shared by Owners and Charterers." },

  // Cl.21 – Commission
  { q:"Cl.21: If the full hire is not paid due to a breach of Charter Party, who must indemnify the brokers for their lost commission?", opts:["Always the Owners","Always the Charterers","The party liable for the breach","Both parties equally"], ans:2, exp:"Cl.21: If the full hire is not paid owing to breach, the PARTY LIABLE THEREFOR shall indemnify the Brokers against their loss of commission." },
];

const RD_QUIZ = [
  // Cl.31 – Bunker on Delivery/Redelivery (3 questions)
  { q:"Rider Cl.31: What is the minimum VLSFO quantity required on board at redelivery?", opts:["200 MT","300 MT","400 MT","500 MT"], ans:2, exp:"Rider Cl.31: redelivery bunkers must include not less than VLSFO 400 MTs and LSMGO 50 MTs. This ensures the vessel can reach the nearest bunkering port after redelivery. Price is settled at Platts Oilgram mean price on the redelivery date." },
  { q:"Rider Cl.31: Bunkers on delivery are valued at USD 600/MT (Platts mean price on delivery date). When is this payment due?", opts:["Immediately on delivery","Together with the first hire payment","Together with the second hire payment","At redelivery, netted off against redelivery bunkers"], ans:2, exp:"Rider Cl.31: payment for bunkers on delivery is made together with the second hire payment. Redelivery bunker value is deducted from the last sufficient hire payment. This avoids separate payments and simplifies cash flow at both ends of the charter." },
  { q:"Rider Cl.31: The delivery date falls on a Sunday (non-working day). Which Platts price is used for bunker valuation?", opts:["The previous Friday's price","The following Monday's price","The mean of Friday and Monday prices (if equal interval)","A price agreed separately by the parties"], ans:2, exp:"Rider Cl.31: if the delivery/redelivery date is not a working day, the price is either the nearest working day's Platts mean, or the average of the two surrounding working days' prices if the interval is equal." },

  // Cl.34 – Trading Limits (3 questions)
  { q:"Rider Cl.34: Charterers wish to call Kaohsiung (Taiwan) then immediately Shanghai (P.R.C.). Is this permitted?", opts:["Yes — both are within INL/IWL","No — direct P.R.C./Taiwan call requires approval from both governments","Yes — with 30 days' notice to Owners","Only if in ballast"], ans:1, exp:"Rider Cl.34: direct call at P.R.C. and Taiwan (or vice versa) is expressly prohibited unless approved by both countries' governmental authorities. This is a hard restriction Charterers cannot waive unilaterally." },
  { q:"Rider Cl.34: The vessel is ordered to Vladivostok (Russia). Is this within the permitted trading range?", opts:["No — all Russian ports are excluded","Yes — Vostochniy and Vladivostok are specifically permitted despite the general CIS exclusion","Only if UN sanctions do not apply","Yes — Russia is not listed as excluded"], ans:1, exp:"Rider Cl.34 excludes CIS (former Soviet states including Russia) from trading, but expressly carves out Vostochniy and Vladivostok as permitted ports. Charterers may call at these two Russian ports without breach." },
  { q:"Rider Cl.34: What is 'Cabotage trading' and why is it excluded?", opts:["Trading between a country's own domestic ports — excluded because it requires special national licences Owners may not hold","Trading in war risk areas — excluded for safety reasons","Trading below a certain cargo volume — excluded for commercial reasons","Trading without a B/L — excluded for legal reasons"], ans:0, exp:"Cabotage = domestic coastal trade within a single country (e.g. port-to-port within China). It is expressly excluded from Rider Cl.34 because cabotage typically requires special domestic licences, flag requirements, or crew nationality rules that the vessel/Owners may not satisfy." },

  // Cl.49 – Cancellation (2 questions)
  { q:"Rider Cl.49: Vessel is off-hire for 27 consecutive days due to unexpected engine failure. What right do Charterers have?", opts:["Claim damages only","Cancel the C/P provided vessel is empty; receive full refund of prepaid hire","Suspend hire indefinitely","Request a replacement vessel"], ans:1, exp:"Rider Cl.49: if off-hire exceeds 25 consecutive days (excluding scheduled drydocking/maintenance), Charterers may cancel — provided the vessel is empty. All prepaid hire must be immediately refunded. This is Charterers' option, not automatic termination." },
  { q:"Rider Cl.49: The vessel has been off-hire for 26 days. There is cargo on board. Can Charterers cancel?", opts:["Yes — 26 days is close enough","No — the vessel must be empty to trigger the cancellation option","Yes — but only partial cancellation","No — 26 days is below the 25-day threshold"], ans:1, exp:"Rider Cl.49 has two requirements: (1) off-hire must exceed 25 consecutive days, and (2) the vessel must be empty. With cargo on board, the cancellation option is not available regardless of how long the off-hire continues." },

  // Cl.61 – Stowaways (2 questions)
  { q:"Rider Cl.61(AA): A stowaway hides in a sealed Charterers' container. Vessel detained 3 days. Who pays and is the vessel off-hire?", opts:["Owners pay; vessel off-hire","Charterers pay all costs; vessel remains on hire","Split equally; off-hire for 50% of detention","Charterers pay; vessel off-hire"], ans:1, exp:"Rider Cl.61(AA): stowaways in Charterers' goods/containers = Charterers' breach. All time, costs and fines for Charterers' account. Vessel remains on hire throughout. Charterers must provide bail if vessel arrested." },
  { q:"Rider Cl.61(BB): A stowaway boards via the anchor chain (not via cargo). Despite Owners' due diligence. Vessel detained. Is the vessel off-hire?", opts:["No — Owners are never responsible for stowaways","Yes — vessel off-hire; all costs for Owners' account","Charterers bear 50% as the vessel was under their employment","No — vessel remains on hire; Charterers manage the situation"], ans:1, exp:"Rider Cl.61(BB): if stowaways gain access by means other than Charterers' cargo/containers (e.g. via anchor chain, gangway), and Owners exercised due diligence, all costs and fines are for Owners' account and the vessel is off-hire. Owners must also provide bail if arrested." },

  // Cl.67 – Reefer (3 questions)
  { q:"Rider Cl.67: Reefer containers malfunction due to a main switchboard failure. Who is liable?", opts:["Charterers — they control the cargo","Owners — power failure is the one exception where Owners bear liability","Split 50/50","The reefer equipment manufacturer"], ans:1, exp:"Rider Cl.67 is explicit: Owners are only responsible for reefer malfunction caused by power failure. All other causes are Charterers' risk. Repair labour at USD 10/man-hour against signed time sheets; spare parts for Charterers' account. No direct cash to Master." },
  { q:"Rider Cl.67: A reefer compressor fails (not due to power failure). The Master arranges emergency repairs using Charterers' spare parts. What is the correct payment procedure?", opts:["Master requests cash from Charterers directly","Charterers pay USD 10/man-hour against a time sheet signed by the Master or Chief Officer; no direct payment to Master","Owners arrange and pay; recover from Charterers later","Costs split equally between parties"], ans:1, exp:"Rider Cl.67: repair labour is charged at USD 10/man-hour. Payment requires a time sheet signed by the Master or Chief Officer as supporting documentation. No funds are to be paid directly to the Master — all settlement is between Charterers and Owners." },
  { q:"Rider Cl.67: How often must Owners monitor reefer performance, and what must Charterers provide before loading?", opts:["Once daily; verbal instructions","Minimum twice daily (weather permitting); written cooling and ventilation instructions before loading","Weekly; no advance instructions needed","Once per port call; instructions at loading time"], ans:1, exp:"Rider Cl.67: Owners must monitor reefer performance at least twice daily (weather and sea conditions permitting). Charterers must provide written cooling and ventilation instructions to the Master before loading reefer containers." },

  // Cl.75 – CONWARTIME (2 questions)
  { q:"Rider Cl.75 (CONWARTIME 2004): Charterers order the vessel to a JWC-listed port. War risk underwriters impose an additional premium. Who pays?", opts:["Owners — part of vessel insurance costs","Charterers — premium from their employment orders; reimbursed at next hire","Split equally","The P&I Club absorbs the extra cost"], ans:1, exp:"Rider Cl.75: additional war risk insurance premiums resulting from Charterers' employment orders are for Charterers' account, reimbursed at the next hire payment. The same applies to crew bonuses/extra wages arising from trading in war risk areas." },
  { q:"Rider Cl.75: The Master refuses to proceed to a Gulf of Aden port, citing safety concerns. Is this a breach of charter?", opts:["Yes — the Master must follow Charterers' employment orders","No — Cl.75 gives Owners the right to refuse entry into areas deemed dangerous; actions under Cl.75 do not constitute deviation","Yes — unless the port is on the JWC war risk list","No — but Owners must pay damages for the refusal"], ans:1, exp:"Rider Cl.75: actions taken by Owners/Master under the CONWARTIME clause (including refusing to enter dangerous areas) shall not be considered deviation and shall constitute due performance of the Charter Party. The Master's safety judgment is protected." },

  // Cl.83 – US Anti-Drug (2 questions)
  { q:"Rider Cl.83 (Anti-Drug): Unmanifested narcotics are found in Charterers' cargo hold. The vessel is detained. Is the vessel off-hire?", opts:["Yes — any detention triggers off-hire","No — vessel remains on hire; all fines and costs for Charterers' account","Charterers can elect to treat detention as off-hire","Off-hire only if detention exceeds 48 hours"], ans:1, exp:"Rider Cl.83: Charterers' non-compliance with the highest degree of anti-drug diligence = breach of warranty. All fines, time lost and costs are for Charterers' account. The vessel remains on hire. Charterers must provide bail if arrested." },
  { q:"Rider Cl.83: Narcotics are found in the personal effects of a crew member. Who bears liability?", opts:["Charterers — they are operating the vessel","Owners — crew are Owners' servants; Owners bear responsibility for crew possession","Split equally","The Master personally"], ans:1, exp:"Rider Cl.83 draws a clear distinction: if drugs are found in Charterers' cargo = Charterers' liability. If drugs are found in the possession of vessel's personnel (crew) = Owners' responsibility. This is an important carve-out protecting Charterers from crew misconduct." },

  // Cl.88 – US 24-Hour Rule (2 questions)
  { q:"Rider Cl.88 (US 24-Hour Rule): Charterers fail to file AMS on time. Vessel arrested by US Customs. Is the vessel off-hire?", opts:["Yes — US detention always triggers off-hire","No — vessel remains on hire; Charterers must provide bail and secure release","Charterers can elect to treat detention as off-hire","Off-hire only after 72 hours"], ans:1, exp:"Rider Cl.88(C): even if the vessel is detained or arrested due to Charterers' non-compliance, the vessel shall remain on hire. Charterers must at their expense take all reasonable steps to secure prompt release and provide bail." },
  { q:"Rider Cl.88: The vessel loads cargo in Los Angeles destined for Japan. Does the US 24-hour rule apply?", opts:["No — the cargo is not destined for a US port","Yes — the rule applies to cargo loaded in any US port, regardless of destination","Only if the cargo transits another US port","Only for cargo valued above USD 10,000"], ans:1, exp:"Rider Cl.88 applies whenever cargo is loaded in a US port — regardless of the destination. The AMS filing requirement applies to all outbound US cargo. Charterers must ensure SCAC codes and ICB are in place before loading in the US (see also Rider Cl.93)." },

  // Cl.96 – SSS Slow Steaming (2 questions)
  { q:"Rider Cl.96 (SSS): Charterers instruct slow steaming below warranted speed. Does Owners have a performance claim under BOXTIME Cl.9?", opts:["Yes — Owners can deduct time for unwarranted slow steaming","No — Cl.96 compliance overrides the due despatch obligation","Only if a B/L has been issued to a third party","Depends on whether cargo is time-sensitive"], ans:1, exp:"Rider Cl.96(E): provided the Master exercises due diligence following Charterers' written slow steaming instructions, there is no breach of any due despatch obligation. Note: subclauses (E) and (F) do not apply in liner trade." },
  { q:"Rider Cl.96: What is the difference between 'slow steaming' (Cl.96(A)(i)) and 'ultra-slow steaming' (Cl.96(A)(ii))?", opts:["Speed below 10 knots vs below 8 knots","Slow steaming keeps engine above auxiliary blower cut-out point; ultra-slow may operate below cut-out point","Slow steaming requires 24hrs notice; ultra-slow requires 48hrs notice","Slow steaming is Charterers' right; ultra-slow requires Owners' consent"], ans:1, exp:"Rider Cl.96: (i) slow steaming = engine stays above auxiliary blower cut-out point; (ii) ultra-slow steaming = engine may operate below cut-out point. Both require written instructions from Charterers and must remain within manufacturer's recommendations. Subclauses are alternatives — delete whichever does not apply; (i) applies if neither is deleted." },

  // Cl.98 – 2020 Sulphur (2 questions)
  { q:"Rider Cl.98 (2020 Sulphur): Charterers supply 0.50% sulphur VLSFO. Vessel is found non-compliant in an ECA zone. Who is liable?", opts:["Charterers — they supplied the fuel","Owners — they warranted vessel compliance with sulphur requirements","Split equally per MARPOL","The bunker supplier only"], ans:1, exp:"Rider Cl.98: if Charterers supply compliant fuel per the clause, Charterers are not liable for Owners' failure to comply. Owners warrant the vessel can consume and comply with sulphur requirements. In ECAs (0.10%), the vessel must use appropriate low-sulphur fuel — Owners are responsible for vessel technical compliance." },
  { q:"Rider Cl.98: Charterers supply non-compliant fuel. The vessel receives a port state fine. Who pays, and is the vessel off-hire?", opts:["Owners pay; vessel off-hire","Charterers indemnify Owners for all losses; vessel remains on hire","Split equally","The bunker supplier pays directly"], ans:1, exp:"Rider Cl.98: if Charterers supply non-compliant fuel, Charterers must indemnify Owners against all resulting losses, damages, delays, fines and claims. The vessel remains on hire throughout. Charterers' obligation to supply compliant fuel is a strict warranty." },

  // Cl.62 – Sale Clause (1 question)
  { q:"Rider Cl.62: Owners wish to sell the vessel mid-charter. What notice must they give, and how long do Charterers have to respond?", opts:["14 days notice; 7 days to respond","30 days notice; 10 running days to respond (not unreasonably withheld)","60 days notice; 30 days to respond","No minimum notice; Charterers have no veto"], ans:1, exp:"Rider Cl.62: minimum 30 days' prior written notice required. Charterers must declare approval/rejection within 10 running days — and shall not unreasonably withhold consent. A tripartite agreement (Owners/Buyers/Charterers) is required to transfer the charter." },

  // Cl.35 – Hire Payment (1 question)
  { q:"Rider Cl.35: The receiving bank deducts a SWIFT charge from the hire payment. Who bears this?", opts:["Charterers — all banking charges are their responsibility","Owners — charges inside the receiving bank are for Owners' account","Split equally","Whoever the bank charges first"], ans:1, exp:"Rider Cl.35: charges outside the receiving bank (e.g. correspondent/intermediary bank fees) = Charterers' account. Charges inside the receiving bank (e.g. incoming SWIFT processing fees) = Owners' account." },

  // Cl.43 – Blockade/Boycott (1 question)
  { q:"Rider Cl.43: Port workers refuse to handle the vessel because of its flag. Hire is USD 20,000/day. What happens to hire during the boycott?", opts:["Hire continues — this is a commercial risk for Charterers","Hire ceases from the start of the boycott; Owners also reimburse Charterers' directly incurred costs","Hire is reduced by 50% during the boycott","Hire continues but Owners compensate Charterers for cargo delays"], ans:1, exp:"Rider Cl.43: if loss of time is caused solely by a boycott due to the vessel's flag, crew terms, or previous trading, hire ceases from commencement of the boycott until work resumes. Owners must also reimburse Charterers for directly incurred expenses from the blockade/boycott." },

  // Cl.86 – Bunker Quality (1 question)
  { q:"Rider Cl.86: How long must bunker samples be retained on board after delivery, and what happens if there is a quality dispute?", opts:["30 days; dispute resolved by Master's log","90 days (or longer if dispute active); dispute resolved by analysis by a mutually agreed analyst whose findings are conclusive","60 days; dispute referred to P&I Club","Until redelivery; resolved by London arbitration"], ans:1, exp:"Rider Cl.86: bunker samples must be retained for 90 days after delivery (extended if a dispute is already in progress). Any dispute about whether fuel meets agreed specifications is settled by analysis by a mutually agreed fuels analyst, whose findings are conclusive evidence." },

  // Cl.23 – Vessel Description / Speed & Consumption
  { q:"Rider Cl.23: The vessel fails to maintain the warranted speed due to heavy weather. Under what condition is the speed warranty suspended?", opts:["When wind exceeds Beaufort Scale 3","When wind exceeds Beaufort Scale 4","When wind exceeds Beaufort Scale 5","The warranty is never suspended"], ans:2, exp:"Rider Cl.23: The speed warranty applies in good weather, typically defined as winds not exceeding Beaufort Scale 4 or 5 (as specified). In heavier conditions the warranty is suspended." },
  { q:"Rider Cl.23: The vessel's actual fuel consumption exceeds the warranted amount. Who bears the cost of the excess bunkers consumed?", opts:["Charterers","Owners","Split equally","The bunker supplier"], ans:1, exp:"Rider Cl.23: If consumption exceeds the warranty, the cost of excess fuel is for the OWNERS' account — they must compensate Charterers for the extra bunkers used." },

  // Cl.27 – Watchmen
  { q:"Rider Cl.27: Compulsory shore gangway watchmen are required in port. How is the cost shared?", opts:["Owners pay 100%","Charterers pay 100%","Split equally 50/50","Split based on time on/off hire"], ans:2, exp:"Rider Cl.27 (and Cl.15(b)): The cost of compulsory shore gangway watchmen shall be borne equally between the Owners and the Charterers." },

  // Cl.29 – Victualling
  { q:"Rider Cl.29: Charterers request that their port captain be victualled on board. The rate per meal is stated in Box 29. Who pays?", opts:["Owners","Charterers","Split equally","The port captain personally"], ans:1, exp:"Rider Cl.29 / Cl.13(i): When requested and authorized, the Owners shall victual Charterers' officials at the rate per person per meal as indicated in Box 29 — at CHARTERERS' expense." },

  // Cl.36 – Cancelling
  { q:"Rider Cl.36: Owners give advance notice that the vessel will not be ready by the cancelling date. Within how many hours must Charterers declare whether they cancel or accept delivery?", opts:["24 hours","48 hours","72 hours","96 hours"], ans:1, exp:"Rider Cl.36 / Cl.1(b): If Owners give notice before the cancelling date, Charterers shall declare within 48 HOURS whether they cancel or will take delivery, without prejudice to their right to claim proved damages." },

  // Cl.37 – Off Hire Bunkers
  { q:"Rider Cl.37: The vessel goes off-hire for engine repairs. Who pays for bunkers consumed during the off-hire period?", opts:["Owners","Charterers","Split equally","Whoever caused the off-hire"], ans:0, exp:"Rider Cl.37: During off-hire periods, bunkers consumed are for the OWNERS' account, as the vessel is not performing services for the Charterers." },

  // Cl.40 – Both-to-Blame Collision
  { q:"Rider Cl.40: A collision occurs and the other vessel is partly at fault. Under the 'Both-to-Blame Collision' clause, what are Charterers obliged to do?", opts:["Sue the other vessel directly","Indemnify Owners against recoveries by the other vessel under cargo claims","Pay all collision costs","Do nothing — it is Owners' problem"], ans:1, exp:"Rider Cl.40 (Both-to-Blame): Charterers shall indemnify Owners against any sum they are required to pay to the other vessel's owners as a result of cargo claims recovered against the colliding vessel." },

  // Cl.44 – Ice Clause
  { q:"Rider Cl.44: The vessel is ordered to a port that subsequently becomes icebound. Who decides whether the vessel shall attempt to enter?", opts:["Charterers","The Master, at his absolute discretion","Owners","The port authority"], ans:1, exp:"Rider Cl.44: The Master shall have absolute discretion whether to attempt to enter, remain in, or proceed through ice-bound waters — the Master's decision prevails for safety." },

  // Cl.45 – General Average
  { q:"Rider Cl.45: General Average is to be adjusted at the place indicated in Box 33. According to which rules?", opts:["Hamburg Rules","York-Antwerp Rules 1974 or any amendment thereto","Hague-Visby Rules","Rotterdam Rules"], ans:1, exp:"Rider Cl.45 / Cl.14(c): General average shall be adjusted according to the York-Antwerp Rules 1974 or any amendment thereto." },

  // Cl.50 – New Jason Clause
  { q:"Rider Cl.50 (New Jason Clause): In the event of danger to the vessel, what does this clause allow Owners to do?", opts:["Abandon the cargo","Claim General Average contributions from cargo interests even if the danger arose from negligent navigation","Cancel the charter","Deviate without consent"], ans:1, exp:"Rider Cl.50: The New Jason Clause allows Owners to collect General Average contributions from cargo interests even when the casualty arose from navigational negligence — overriding the common law rule that denied GA in such cases." },

  // Cl.51 – Himalaya Clause
  { q:"Rider Cl.51 (Himalaya/Circular Indemnity Clause): What protection does this clause extend to the Owners?", opts:["Owners can limit cargo liability to USD 500 per package","Owners enjoy the same defences and immunities as apply under the bill of lading against third party claims","Owners are exempt from all cargo liability","Owners can reroute the vessel freely"], ans:1, exp:"Rider Cl.51 (Himalaya): This clause extends the benefit of the bill of lading terms, conditions, and limitations — including liability caps — to the Owners as against third party tortious claims." },

  // Cl.52 – Sister Ship Salvage
  { q:"Rider Cl.52 (Sister Ship Salvage Clause): A sister vessel owned by the same Owners saves this vessel. Can salvage be claimed?", opts:["No, same owner vessels cannot claim salvage from each other","Yes, this clause allows salvage claims between vessels under common ownership","Only if the master requests it","Only if cargo is involved"], ans:1, exp:"Rider Cl.52: The Sister Ship Salvage clause allows Owners to claim salvage remuneration even when the saving vessel and the vessel saved are under common ownership, as if they were owned by different parties." },

  // Cl.53 – Lien Clause
  { q:"Rider Cl.53: Owners have a lien on Charterers' goods and containers. What can Owners exercise this lien for?", opts:["Any debt owed by Charterers to any party","Unpaid charter hire, unreimbursed Owners' expenses paid on behalf of Charterers, and GA contributions","Damage caused by stevedores only","Fuel costs only"], ans:1, exp:"Rider Cl.53 / Cl.14(e): Owners have a lien on Charterers' goods, containers, and sub-freights/sub-hire for: unpaid charter hire, unreimbursed Charterers' expenses initially paid by Owners, and GA contributions properly due." },

  // Cl.57 – Freight Tax
  { q:"Rider Cl.57: A freight tax is levied on hire at the port of loading. Who is responsible for paying this tax?", opts:["Owners","Charterers","Split equally","The cargo shipper"], ans:1, exp:"Rider Cl.57: Any freight tax, income tax or similar tax levied on hire earned under this Charter Party is for the CHARTERERS' account unless it is a tax on Owners' income in Owners' country." },

  // Cl.60 – Cargo Gear
  { q:"Rider Cl.60: The vessel's crane breaks down during cargo operations at a port with no shore cranes available. What happens to hire?", opts:["Full hire continues","Hire is reduced pro rata based on hatches affected","Hire ceases completely","Hire is suspended for 24 hours only"], ans:1, exp:"Rider Cl.60 / Cl.11(b): If shore cranes are not available during stoppage of the vessel's gear, the vessel is pro-rata off hire — hire reduced in proportion to the number of hatches affected." },

  // Cl.64 – Hazardous Goods
  { q:"Rider Cl.64: Hazardous goods must be documented and handled according to which international regulations?", opts:["SOLAS only","IMO regulations and any mandatory local requirements and regulations of the flag state","MARPOL only","IMDG Code only"], ans:1, exp:"Rider Cl.64 / Cl.4(b): Hazardous goods must be loaded, stowed, discharged and documented in accordance with IMO regulations, any mandatory local requirements and regulations of the flag state." },

  // Cl.68 – Speed and Performance
  { q:"Rider Cl.68: The vessel consistently under-performs on speed. Charterers claim a hire deduction. What must Charterers prove to support their claim?", opts:["Only that the vessel was slow","Actual underperformance against the warranted speed and consumption, supported by voyage data","That the Master failed to give full orders","That the vessel is unclassed"], ans:1, exp:"Rider Cl.68: Charterers must demonstrate actual underperformance compared to the warranted speed/consumption figures, typically using noon reports and voyage data. The burden of proof lies with the claiming party." },

  // Cl.74 – Piracy
  { q:"Rider Cl.74: The vessel transits a piracy high-risk area and Owners incur additional war risk insurance premiums. Who pays?", opts:["Owners","Charterers","Split equally","The P&I Club"], ans:1, exp:"Rider Cl.74 / Cl.6(n) / Cl.19(b): Additional insurance premiums (including war risks and piracy zone premiums) incurred by Owners when Charterers order the vessel to such areas are reimbursed by CHARTERERS." },

  // Cl.79 – Owners' Liability Cap
  { q:"Rider Cl.79: Owners' liability to Charterers for cargo loss is limited by reference to what basis under Cl.17(c)?", opts:["USD 500 per package regardless","The same basis as applicable under mandatory law between Charterers and a third party under the bill of lading, or GBP 100 per package where no mandatory law applies","The vessel's insured value","The market value of the cargo"], ans:1, exp:"Rider Cl.79 / Cl.17(c)(i): Owners' liability for goods is on the same basis as applicable under mandatory law between Charterers and a third party under a bill of lading with no declared value. Where no mandatory law applies, liability is limited to GB Pounds 100 per package." },
];

