function shuffle(arr) {
  const a = [...arr];
  for (let i = a.length-1; i > 0; i--) {
    const j = Math.floor(Math.random()*(i+1));
    [a[i],a[j]] = [a[j],a[i]];
  }
  return a;
}

function scoreMatch(item, q) {
  const s = q.toLowerCase();
  let sc = 0;
  if (item.label.toLowerCase().includes(s)) sc += 10;
  if (item.title.toLowerCase().includes(s)) sc += 8;
  if (item.en.toLowerCase().includes(s)) sc += 5;
  if (item.zh && item.zh.toLowerCase().includes(s)) sc += 3;
  const costs = [...(item.owner||[]),...(item.charterer||[])].join(" ").toLowerCase();
  if (costs.includes(s)) sc += 3;
  return sc;
}

const STORAGE_KEY = "charter_custom_riders";



function PasswordGate({children}) {
  const [unlocked, setUnlocked] = useState(()=>sessionStorage.getItem("charter_auth")==="1");
  const [pw, setPw] = useState("");
  const [err, setErr] = useState(false);
  if (unlocked) return children;
  return (
    <div style={{minHeight:"100vh",background:"#0d1b2a",display:"flex",alignItems:"center",justifyContent:"center"}}>
      <div style={{background:"#1a2f45",borderRadius:12,padding:"40px 36px",minWidth:320,boxShadow:"0 8px 32px rgba(0,0,0,0.4)",textAlign:"center"}}>
        <div style={{fontSize:22,fontWeight:700,color:"#7ec8e3",marginBottom:8,letterSpacing:1}}>BOXTIME</div>
        <div style={{fontSize:13,color:"#4a6a80",marginBottom:28}}>Charter Party Reference</div>
        <input
          type="password"
          placeholder="Enter password"
          value={pw}
          onChange={e=>{setPw(e.target.value);setErr(false);}}
          onKeyDown={e=>{if(e.key==="Enter"){if(pw==="chartering"){sessionStorage.setItem("charter_auth","1");setUnlocked(true);}else{setErr(true);}}}}
          style={{width:"100%",padding:"10px 14px",borderRadius:8,border:err?"1px solid #e05555":"1px solid #2a4a6a",background:"#0d1b2a",color:"#c8dce8",fontSize:14,outline:"none",boxSizing:"border-box",marginBottom:10}}
          autoFocus
        />
        {err&&<div style={{color:"#e05555",fontSize:12,marginBottom:8}}>Incorrect password</div>}
        <button
          onClick={()=>{if(pw==="chartering"){sessionStorage.setItem("charter_auth","1");setUnlocked(true);}else{setErr(true);}}}
          style={{width:"100%",padding:"10px",borderRadius:8,border:"none",background:"#2a7ab5",color:"white",fontSize:14,fontWeight:600,cursor:"pointer",marginTop:4}}
        >Enter</button>
      </div>
    </div>
  );
}

